import { SxProps, Typography } from '@mui/material';

import { ServiceError } from '@/services/errors/service-error';

export default function CriticalError({
  messagePrefix,
  error,
  sx,
}: {
  messagePrefix?: string;
  error: ServiceError | null;
  sx?: SxProps;
}) {
  return (
    error?.message && (
      <Typography className="data-error" color="error" sx={sx}>
        {messagePrefix ?? ''}
        {error.message}
      </Typography>
    )
  );
}

