        playerId: conditions.playerId,
        offset: conditions.currentPage * conditions.rowsPerPage,
        pageSize: conditions.rowsPerPage,
      },
    );
    if (result.error) {
      setLoadError(result.error);
      return;
    }
    setLoadError(null);
    setResources(result.resources);
    setNumberOfTotalItems(result.total);
  };

  const getPlayers = async () => {
    const result = await services.default.player.getPlayersForMultipleTeams(
      hasSuperUserReadAccess ? null : teams.map((x) => x.id),
      {
        offset: 0,
        pageSize: AppConstants.SEARCH_DEFAULT_BIG_VALUE,
      },
    );
    if (result.error) {
      enqueueSnackbar({
        variant: 'error',
        message: sprintf(
          '%s: %s',
          translate('snackbar_failed_to_get_player_list'),
          result.error.message,
        ),
      });
      return;
    }
    setPlayerOptions(
      result.players.map((x) => {
        return {
          label: x.name,
          id: x.id,
        };
      }),
    );
  };

  const initialize = async () => {
    try {
      getPlayers();
      const parsed = {
        ...parseQueryParam(router.query),
        ...services.localStorage.defaultPaginationData(
          currentUser.id,
          router.query,
        ),
      };
      setConditions({
        ...conditions,
        ...parsed,
      });
      updateQueryParameters({
        ...parsed,
        searchTrigger: new Date(),
      });
    } finally {
      setIsInitialized(true);
    }
  };

  const updateQueryParameters = (
    conds: ResourceQueryCondition & CommonPaginationData,
    forceReplace = false,
  ) => {
    const param = buildQueryParam(conds);
    const pathWithQuery = PAGE_INFO.SUPER_ADMIN_RESOURCES.href(param);
    if (forceReplace) {
      router.replace(pathWithQuery);
      return;
    }
    PathUtil.routerPushOrReplaceWithPaginationData(
      router,
      conds.currentPage,
      pathWithQuery,
    );
  };

  useEffect(() => {
    initialize();
  }, []);

  // This must be configured for browser back.
  useEffect(() => {
    if (!isInitialized) {
      return;
    }
    // Important: Call after setConditions to trigger (*1)
    const parsed = parseQueryParam(router.query);
    setConditions({
      ...conditions,
      ...parsed,
      searchTrigger: new Date(),
    });
  }, [router.query]); // browser back -> trigger by paginationData

  useEffect(() => {
    if (!isInitialized) {
      return;
    }
    getResourcesAndUpdateList();
  }, [conditions.searchTrigger]); // reset

  if (!hasSuperUserReadAccess) {
    return (
      <Container>
        <Alert severity="error">
          このページにアクセスする権限がありません。
        </Alert>
      </Container>
    );
  }

  // useEffect(() => {
  //   const setIntervalFunctionId = setInterval(() => {
  //     logger.debug(`Checking uploaded resources for status...`)
  //     if (document.hidden) {
  //       // logger.debug(`Document is hidden`)
  //       return
  //     }

  //     if (resources.filter(resource => resource.status != RESOURCE_STATUSES.ready.value).length > 0) {
  //       getResourcesAndUpdateList()
  //     }
  //   }, AppConstants.RESOURCE_CHECKING_POLLING_INTERVAL)
  //   return () => clearInterval(setIntervalFunctionId)
  // }, [resources])

  return (
    <Container sx={{ position: 'relative' }}>
      <DefaultBreadCrumbs
        breadcrumbs={[
          {
            name: translate(
              PAGE_INFO.SUPER_ADMIN_RESOURCES.name as keyof typeof translate,
            ),
            link: PAGE_INFO.SUPER_ADMIN_RESOURCES.href(),
          },
        ]}
      />
      <Typography variant="h1">{translate('all_resources')}</Typography>
      <Divider sx={{ mt: 1, mb: 5 }} />

      <Card
        sx={{
          backgroundColor: 'white',
          minWidth: '55rem',
          p: 2,
        }}
      >
        <form
          onSubmit={(e) => {
            e.preventDefault();
            getResourcesAndUpdateList();
          }}
        >
          <Stack direction="row" spacing={1}>
            <FormControl size="small" variant="standard">
              <Select
                value={conditions.sort}
                onChange={(e) => {
                  const newData = {
                    ...conditions,
                    sort: e.target.value as ResourceSortType,
                    currentPage: 0,
                  };
                  setConditions(newData);
                  updateQueryParameters(newData);
                }}
              >
                {sortOptions.map((x) => {
                  return (
                    <MenuItem key={x.value} value={x.value}>
                      {x.name}
                    </MenuItem>
                  );
                })}
              </Select>
            </FormControl>
            <FormControl size="small" variant="standard">
              <Select
                value={conditions.filter}
                onChange={(e) => {
                  const newData = {
                    ...conditions,
                    filter: e.target.value as ResourceDateFilterType,
                    currentPage: 0,
                  };
                  setConditions(newData);
                  updateQueryParameters(newData);
                }}
              >
                {dateFilterOptions.map((x) => {
                  return (
                    <MenuItem key={x.value} value={x.value}>
                      {translate(x.name as keyof typeof translate)}
                    </MenuItem>
                  );
                })}
              </Select>
            </FormControl>
            <Autocomplete
              options={playerOptions}
              value={
                playerOptions?.find((x) => x.id === conditions.playerId) ?? null
              }
              isOptionEqualToValue={(a, b) => a.id === b.id}
              renderInput={(params) => (
                <TextField
                  {...params}
                  placeholder={translate('all_players')}
                  variant="standard"
                />
              )}
              size="small"
              onChange={(e, value) => {
                const newData = {
                  ...conditions,
                  playerId: value?.id ?? null,
                  currentPage: 0,
                };
                setConditions(newData);
                updateQueryParameters(newData);
              }}
            />
            <Box flex={1} />
            <DefaultSearchField
              value={conditions.keyword}
              onSearch={() => {
                const newData = {
                  ...conditions,
                  currentPage: 0,
                };
                updateQueryParameters(newData);
              }}
              onChange={(e) => {
                setConditions({
                  ...conditions,
                  keyword: e.target.value,
                });
              }}
            />
          </Stack>
        </form>

        {loadError ? (
          <CriticalError error={loadError} />
        ) : (
          <MultiTeamsResourceSearchResultTable
            resources={resources}
            resourceSortType={conditions.sort}
          />
        )}

        <CommonPagination
          user={currentUser}
          numberOfTotalItems={numberOfTotalItems}
          commonPaginationData={{
            currentPage: conditions.currentPage,
            rowsPerPage: conditions.rowsPerPage,
          }}
          onChange={(data) => {
            updateQueryParameters({
              ...conditions,
              ...data,
            });
          }}
        />
      </Card>
    </Container>
  );
}

export default function Page() {
  const { router, dispatch } = useServicesHook();

  const currentUser = useSelector((state) => state.user.me);
  const teams = useSelector((state) => state.user.accessibleTeams);
  const currentTeam = useSelector((state) => state.user.currentTeam);
  const modes: SessionDetailPageMode[] = ['upload'];
  const mode: SessionDetailPageMode | null = _.includes(
    modes,
    router.query.mode,
  )
    ? (router.query.mode as SessionDetailPageMode)
    : null;

  return (
    currentUser &&
    currentTeam && (
      <PageInner
        currentUser={currentUser}
        currentTeam={currentTeam}
        mode={mode}
      />
    )
  );
}

Page.getLayout = function getLayout(page: ReactElement) {
  return <ConsoleLayout>{page}</ConsoleLayout>;
};

