toolUseResult.originalFile:
import {
  Alert,
  Box,
  Button,
  Card,
  Chip,
  CircularProgress,
  Container,
  Divider,
  Paper,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Typography,
} from '@mui/material';
import { alpha } from '@mui/material/styles';
import React, {
  ReactElement,
  useCallback,
  useEffect,
  useMemo,
  useState,
} from 'react';

import CriticalError from '@/components/common/critical-error';
import DefaultBreadCrumbs from '@/components/common/default-breadcrumb';
import {
  CommonPagination,
  CommonPaginationData,
} from '@/components/pagination/common-pagination';
import { PAGE_INFO } from '@/constants/page.constants';
import useServicesHook from '@/hooks';
import ConsoleLayout from '@/layouts/console.layout';
import { Item, ItemAiCoach, ItemBall, ItemSubscription } from '@/models/item';
import { ItemDistributionHistory } from '@/models/item-distribution-history';
import { Team } from '@/models/team';
import { User } from '@/models/user';
import { ServiceError } from '@/services/errors/service-error';
import { useSelector } from '@/store';
import { formatValidityPeriod } from '@/utils/formatter';
import { translate } from '@/utils/i18n';
import { StringUtil } from '@/utils/string.util';

import ItemDetailModal from './ItemDetailModal';

type PageInnerProps = {
  currentUser: User;
  currentTeam: Team;
};

function PageInner({ currentUser }: PageInnerProps) {
  const { services, router } = useServicesHook();
  const superAdminService = services.default.superAdmin;
  const pageTitle = translate('item_management');

  const hasSuperUserReadAccess = User.isAccessible(
    currentUser,
    'all',
    'admin',
    'read',
    false,
  );

  const hasSuperUserWriteAccess = User.isAccessible(
    currentUser,
    'all',
    'admin',
    'write',
    false,
  );

  const [items, setItems] = useState<Item[]>([]);
  const [total, setTotal] = useState<number>(0);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [loadError, setLoadError] = useState<ServiceError | null>(null);
  const [pagination, setPagination] = useState<CommonPaginationData>(() =>
    services.localStorage.defaultPaginationData(currentUser.id, router.query),
  );

  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
  const [selectedItem, setSelectedItem] = useState<Item | null>(null);
  const defaultHistoryRowsPerPage = services.localStorage.getNumOfPerPage(
    currentUser.id,
  );
  const [historyPagination, setHistoryPagination] =
    useState<CommonPaginationData>({
      currentPage: 0,
      rowsPerPage: defaultHistoryRowsPerPage,
    });
  const [distributionHistories, setDistributionHistories] = useState<
    ItemDistributionHistory[]
  >([]);
  const [distributionHistoryTotal, setDistributionHistoryTotal] =
    useState<number>(0);
  const [isHistoryLoading, setIsHistoryLoading] = useState<boolean>(false);
  const [historyError, setHistoryError] = useState<ServiceError | null>(null);

  const itemNameMap = useMemo(() => {
    const map: Record<string, string | null> = {};
    items.forEach((entry) => {
      map[entry.id] = entry.name;
    });
    return map;
  }, [items]);

  const renderUsageBlocks = (
    entries: Array<
      Pick<
        ItemAiCoach | ItemBall,
        'id' | 'availableCount' | 'priority' | 'validityPeriod'
      >
    >,
  ) => {
    if (!entries || entries.length === 0) {
      return (
        <Typography variant="body2" color="text.secondary">
          -
        </Typography>
      );
    }

    return (
      <Stack
        spacing={1.5}
        divider={<Divider flexItem sx={{ borderColor: 'divider' }} />}
      >
        {entries.map((entry, index) => (
          <Box key={entry.id ?? index}>
            <Typography variant="subtitle2" color="text.primary">
              {translate('usage')}: {entry.availableCount ?? '-'}
            </Typography>
            <Typography variant="caption" color="text.secondary" sx={{ mr: 1 }}>
              {translate('item_priority')}: {entry.priority ?? '-'}
            </Typography>
            <br/>
            <Typography variant="caption" color="text.secondary">
              {translate('validity_period')}:{' '}
              {formatValidityPeriod(entry.validityPeriod)}
            </Typography>
          </Box>
        ))}
      </Stack>
    );
  };

  const renderSubscriptionBlocks = (
    item: Item,
    subscriptions: ItemSubscription[],
  ) => {
    if (!item.isSubscription) {
      return (
        <Typography variant="body2" color="text.secondary">
          -
        </Typography>
      );
    }
    if (!subscriptions || subscriptions.length === 0) {
      return (
        <Typography variant="body2" color="text.secondary">
          {translate('items_table_no_data')}
        </Typography>
      );
    }

    return (
      <Stack
        spacing={1.5}
        divider={<Divider flexItem sx={{ borderColor: 'divider' }} />}
      >
        {subscriptions.map((subscription, index) => (
          <Box key={subscription.id ?? index}>
            <Typography variant="body2" fontWeight={600} color="text.primary">
              {subscription.name ?? '-'}
            </Typography>
            <Chip
              size="small"
              label={translate(subscription.isPaid ? 'paid' : 'free')}
              sx={(theme) => ({
                mt: 0.5,
                bgcolor: alpha(
                  theme.palette[subscription.isPaid ? 'success' : 'primary']
                    .main,
                  0.12,
                ),
                color:
                  theme.palette[subscription.isPaid ? 'success' : 'primary']
                    .main,
                fontWeight: 600,
                borderRadius: 1,
                width: 'fit-content',
              })}
            />
          </Box>
        ))}
      </Stack>
    );
  };

  const loadItems = useCallback(async () => {
    setIsLoading(true);
    setLoadError(null);
    const response = await superAdminService.getItems({
      offset: pagination.currentPage * pagination.rowsPerPage,
      pageSize: pagination.rowsPerPage,
      orderBy: 'id',
      isOrderDesc: false,
    });
    if (response.error) {
      setLoadError(response.error);
      setItems([]);
      setTotal(0);
      setIsLoading(false);
      return;
    }
    setItems(response.items ?? []);
    setTotal(response.total ?? 0);
    setIsLoading(false);
  }, [pagination.currentPage, pagination.rowsPerPage, superAdminService]);

  const loadDistributionHistory = useCallback(async () => {
    if (historyPagination.rowsPerPage <= 0) {
      setDistributionHistories([]);
      setDistributionHistoryTotal(0);
      return;
    }
    setIsHistoryLoading(true);
    setHistoryError(null);
    const response = await superAdminService.searchItemDistributionHistory({
      page: historyPagination.currentPage,
      pageSize: historyPagination.rowsPerPage,
      orderBy: 'created_at',
      isOrderDesc: true,
    });
    if (response.error) {
      setHistoryError(response.error);
      setDistributionHistories([]);
      setDistributionHistoryTotal(0);
      setIsHistoryLoading(false);
      return;
    }
    setDistributionHistories(response.histories ?? []);
    setDistributionHistoryTotal(response.total ?? 0);
    setIsHistoryLoading(false);
  }, [
    historyPagination.currentPage,
    historyPagination.rowsPerPage,
    superAdminService,
  ]);

  useEffect(() => {
    loadItems();
  }, [loadItems]);

  useEffect(() => {
    loadDistributionHistory();
  }, [loadDistributionHistory]);

  useEffect(() => {
    if (!isModalOpen) {
      setSelectedItem(null);
    }
  }, [isModalOpen]);

  const handleDistributed = useCallback(() => {
    loadItems();
    loadDistributionHistory();
  }, [loadItems, loadDistributionHistory]);

  if (!hasSuperUserReadAccess) {
    return (
      <Container>
        <Alert severity="error">
          このページにアクセスする権限がありません。
        </Alert>
      </Container>
    );
  }

  return (
    <Container sx={{ position: 'relative', mb: 8 }}>
      <DefaultBreadCrumbs
        breadcrumbs={[
          {
            name: pageTitle,
            link: PAGE_INFO.SUPER_ADMIN_ITEMS.href(),
          },
        ]}
      />
      <Stack direction="row" justifyContent="space-between" alignItems="center">
        <Typography variant="h1">{pageTitle}</Typography>
      </Stack>
      <Divider sx={{ mt: 1, mb: 3 }} />

      <Card sx={{ backgroundColor: 'white', p: 2 }}>
        {loadError ? (
          <CriticalError error={loadError} />
        ) : (
          <TableContainer component={Paper} elevation={0}>
            <Table
              size="small"
              sx={{
                tableLayout: 'fixed',
                '.MuiTableCell-root': { overflowWrap: 'anywhere' },
              }}
            >
              <TableHead>
                <TableRow>
                  <TableCell width="35%">{translate('name')}</TableCell>
                  <TableCell width="25%">
                    {translate('items_table_subscriptions')}
                  </TableCell>
                  <TableCell width="15%">
                    {translate('items_table_balls')}
                  </TableCell>
                  <TableCell width="15%">
                    {translate('items_table_ai_coach')}
                  </TableCell>
                  <TableCell width="10%"></TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {isLoading && (
                  <TableRow>
                    <TableCell colSpan={6}>
                      <Box
                        sx={{
                          display: 'flex',
                          justifyContent: 'center',
                          alignItems: 'center',
                          py: 4,
                        }}
                      >
                        <CircularProgress size={24} />
                      </Box>
                    </TableCell>
                  </TableRow>
                )}
                {!isLoading && items.length === 0 && (
                  <TableRow>
                    <TableCell colSpan={6}>
                      <Typography align="center" sx={{ py: 4 }}>
                        {translate('items_table_no_data')}
                      </Typography>
                    </TableCell>
                  </TableRow>
                )}
                {!isLoading &&
                  items.map((item) => {
                    return (
                      <TableRow
                        key={item.id}
                        hover
                        sx={{
                          transition: (theme) =>
                            theme.transitions.create('background-color'),
                          '&:hover': {
                            bgcolor: (theme) =>
                              theme.palette.mode === 'light'
                                ? alpha(theme.palette.primary.light, 0.08)
                                : alpha(theme.palette.primary.dark, 0.2),
                          },
                        }}
                      >
                        <TableCell sx={{ minWidth: '14rem' }}>
                          <Typography
                            variant="body1"
                            fontWeight={600}
                            color="primary.main"
                          >
                            {item.name}
                          </Typography>
                        </TableCell>
                        <TableCell sx={{ minWidth: '14rem' }}>
                          {renderSubscriptionBlocks(item, item.subscriptions)}
                        </TableCell>
                        <TableCell sx={{ minWidth: '16rem' }}>
                          {renderUsageBlocks(item.balls)}
                        </TableCell>
                        <TableCell sx={{ minWidth: '16rem' }}>
                          {renderUsageBlocks(item.aiCoachs)}
                        </TableCell>
                        <TableCell align="right">
                          <Button
                            size="small"
                            variant="text"
                            onClick={() => {
                              setSelectedItem(item);
                              setIsModalOpen(true);
                            }}
                          >
                            {translate('item_details')}
                          </Button>
                        </TableCell>
                      </TableRow>
                    );
                  })}
              </TableBody>
            </Table>
          </TableContainer>
        )}
      </Card>

      {total > 0 && (
        <Box sx={{ display: 'flex', justifyContent: 'flex-end', mt: 2 }}>
          <CommonPagination
            commonPaginationData={pagination}
            numberOfTotalItems={total}
            onChange={setPagination}
            user={currentUser}
          />
        </Box>
      )}

      <Card sx={{ backgroundColor: 'white', p: 2, mt: 4 }}>
        <Typography variant="h5">
          {translate('item_distribution_history')}
        </Typography>
        <Divider sx={{ mt: 1, mb: 2 }} />
        {historyError ? (
          <CriticalError error={historyError} />
        ) : (
          <TableContainer component={Paper} elevation={0}>
            <Table
              size="small"
              sx={{
                tableLayout: 'fixed',
                '.MuiTableCell-root': { overflowWrap: 'anywhere' },
              }}
            >
              <TableHead>
                <TableRow>
                  <TableCell>{translate('name')}</TableCell>
                  <TableCell>{translate('start_datetime')}</TableCell>
                  <TableCell>{translate('end_datetime')}</TableCell>
                  <TableCell>{translate('team_type')}</TableCell>
                  <TableCell>
                    {translate('item_distribution_history_distributed_at')}
                  </TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {isHistoryLoading && (
                  <TableRow>
                    <TableCell colSpan={5}>
                      <Box
                        sx={{
                          display: 'flex',
                          justifyContent: 'center',
                          alignItems: 'center',
                          py: 4,
                        }}
                      >
                        <CircularProgress size={24} />
                      </Box>
                    </TableCell>
                  </TableRow>
                )}
                {!isHistoryLoading && distributionHistories.length === 0 && (
                  <TableRow>
                    <TableCell colSpan={5}>
                      <Typography align="center" sx={{ py: 4 }}>
                        {translate('items_table_no_data')}
                      </Typography>
                    </TableCell>
                  </TableRow>
                )}
                {!isHistoryLoading &&
                  distributionHistories.map((history) => {
                    const historyName = itemNameMap[history.itemId] ?? null;
                    return (
                      <TableRow key={history.id}>
                        <TableCell>
                          <Stack spacing={0.5}>
                            <Typography
                              variant="body1"
                              fontWeight={600}
                              color="text.primary"
                            >
                              {historyName ?? '-'}
                            </Typography>
                            <Typography
                              variant="caption"
                              color="text.secondary"
                            >
                              {history.itemId}
                            </Typography>
                          </Stack>
                        </TableCell>
                        <TableCell>
                          <Typography variant="body2">
                            {StringUtil.getPeriodDispString(
                              history.startDate ?? null,
                            )}
                          </Typography>
                        </TableCell>
                        <TableCell>
                          <Typography variant="body2">
                            {StringUtil.getPeriodDispString(
                              history.endDate ?? null,
                            )}
                          </Typography>
                        </TableCell>
                        <TableCell>
                          <Typography variant="body2">
                            {StringUtil.getTeamTypeString(history.teamType)}
                          </Typography>
                        </TableCell>
                        <TableCell>
                          <Typography variant="body2">
                            {StringUtil.getPeriodDispString(
                              history.createdAt ?? null,
                            )}
                          </Typography>
                        </TableCell>
                      </TableRow>
                    );
                  })}
              </TableBody>
            </Table>
          </TableContainer>
        )}
        {distributionHistoryTotal > 0 && !historyError && (
          <Box sx={{ display: 'flex', justifyContent: 'flex-end', mt: 2 }}>
            <CommonPagination
              commonPaginationData={historyPagination}
              numberOfTotalItems={distributionHistoryTotal}
              onChange={setHistoryPagination}
              user={currentUser}
            />
          </Box>
        )}
      </Card>

      <ItemDetailModal
        isOpen={isModalOpen && !!selectedItem}
        setIsOpen={setIsModalOpen}
        item={selectedItem}
        onDistributed={handleDistributed}
        hasSuperUserWriteAccess={hasSuperUserWriteAccess}
      />
    </Container>
  );
}

export default function Page() {
  const currentUser = useSelector((state) => state.user.me);
  const currentTeam = useSelector((state) => state.user.currentTeam);
  return (
    currentUser &&
    currentTeam && (
      <PageInner currentUser={currentUser} currentTeam={currentTeam} />
    )
  );
}

Page.getLayout = function getLayout(page: ReactElement) {
  return <ConsoleLayout>{page}</ConsoleLayout>;
};

