                    {translate('item_distribution_history_distributed_at')}
                  </TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {isHistoryLoading && (
                  <TableRow>
                    <TableCell colSpan={5}>
                      <Box
                        sx={{
                          display: 'flex',
                          justifyContent: 'center',
                          alignItems: 'center',
                          py: 4,
                        }}
                      >
                        <CircularProgress size={24} />
                      </Box>
                    </TableCell>
                  </TableRow>
                )}
