import { EditCalendar } from '@mui/icons-material';
import {
  Autocomplete,
  Box,
  Button,
  Card,
  Container,
  Divider,
  FormControl,
  Grid2 as Grid,
  MenuItem,
  Select,
  Stack,
  TextField,
  Typography,
} from '@mui/material';
import _ from 'lodash';
import { enqueueSnackbar } from 'notistack';
import React, { ReactElement, useEffect, useMemo, useState } from 'react';
import { sprintf } from 'sprintf-js';

import AccessDenied from '@/components/common/access-denied';
import CriticalError from '@/components/common/critical-error';
import DefaultBreadCrumbs from '@/components/common/default-breadcrumb';
import { FloatingButton } from '@/components/common/floating-button';
import DefaultSearchField from '@/components/common/input/default-search-field';
import { ConfirmationModal } from '@/components/modal/confirmation-modal';
import { SessionCreationModal } from '@/components/modal/session/session-creation-modal';
import { SessionUpdateModal } from '@/components/modal/session/session-update-modal';
import {
  CommonPagination,
  CommonPaginationData,
} from '@/components/pagination/common-pagination';
import { SessionSearchResultTable } from '@/components/sessions/session-search-result-table';
import { TeamPlanLimitBand } from '@/components/sessions/team-plan-limit-band';
import AppConstants, {
  AppDefaultSelectOptions,
} from '@/constants/app.constants';
import { PAGE_INFO } from '@/constants/page.constants';
import useServicesHook from '@/hooks';
import ConsoleLayout from '@/layouts/console.layout';
import { Session } from '@/models/session';
import { Team, TeamType } from '@/models/team';
import { User } from '@/models/user';
import { ServiceError } from '@/services/errors/service-error';
import {
  SessionDateFilterType,
  sessionDefaultDateOptions,
  SessionSortType,
  sessionSortTypes,
} from '@/services/interfaces/sessions-api.interface';
import { useSelector } from '@/store';
import { wrapForLoading } from '@/utils/functions/transformer';
import { translate } from '@/utils/i18n';
import { logger } from '@/utils/logger';
import { PathUtil } from '@/utils/path.util';

type SessionQueryCondition = {
  keyword: string;
  sort: SessionSortType;
  filter: SessionDateFilterType;
  playerId: string | null;
  location: string | null;
  searchTrigger: Date;
};

// This constant value is used to distinguish "All locations" from other location values.
const VALUE_FOR_ALL_LOCATIONS = '_all_locations_';
const ID_OF_ALL_PLAYER = '-';

const defaultCondition: SessionQueryCondition & CommonPaginationData = {
  keyword: '',
  sort: 'recent',
  filter: 'all',
  playerId: ID_OF_ALL_PLAYER,
  location: null,
  currentPage: 0,
  rowsPerPage: 10,

  searchTrigger: new Date(),
};

const buildQueryParam = (
  data: SessionQueryCondition & CommonPaginationData,
) => {
  return {
    keyword: data.keyword.toString(),
    sort: data.sort.toString(),
    filter: data.filter.toString(),
    playerId: data.playerId?.toString() ?? '',
    location: data.location ?? undefined,
    page: data.currentPage.toString(),
    pageSize: data.rowsPerPage.toString(),
  };
};

const parseQueryParam = (data: any) => {
  return _.chain({
    keyword: PathUtil.getStringFromQuery(data.keyword),
    sort: PathUtil.getEnumFromQuery(sessionSortTypes, data.sort),
    filter: PathUtil.getEnumFromQuery(sessionDefaultDateOptions, data.filter),
    playerId: PathUtil.getUUIDFromQuery(data.playerId),
    location:
      data.location === '' ? '' : PathUtil.getStringFromQuery(data.location),
    currentPage: PathUtil.getIntFromQuery(data.page),
    rowsPerPage: PathUtil.getIntFromQuery(data.pageSize),
  })
    .omitBy((v) => {
      return _.isNil(v);
    })
    .defaultsDeep(defaultCondition)
    .value();
};

function PageInner({
  currentUser,
  currentTeam,
}: {
  currentUser: User;
  currentTeam: Team;
}) {
  const { services, router, reloader } = useServicesHook();
  const unit = useSelector((state) => state.user.unit);

  const teamId = currentTeam.id;

  const [isInitialized, setIsInitialized] = useState<boolean>(false);
  const [loadError, setLoadError] = useState<ServiceError | null>(null);
  const [sessions, setSessions] = useState<Session[]>([]);
  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
  const [conditions, setConditions] = useState<
    SessionQueryCondition & CommonPaginationData
  >({
    ...defaultCondition,
    ...parseQueryParam(router.query),
    ...services.localStorage.defaultPaginationData(
      currentUser.id,
      router.query,
    ),
  });
  const [numberOfTotalItems, setNumberOfTotalItems] = useState<number>(0);
  const [playerOptions, setPlayerOptions] = useState<
    { id: string; label: string }[]
  >([]);

  // edit modal
  const [isEditSessionModalOpen, setIsEditSessionModalOpen] =
    useState<boolean>(false);
  const [editingSession, setEditingSession] = useState<Session | null>(null);
  const [isCsvDownloading, setIsCsvDownloading] = useState<boolean>(false);

  const [confirmModalDataIsOpen, setConfirmModalDataIsOpen] =
    useState<boolean>(false);

  const [confirmModalData, setConfirmModalData] = useState<{
    cbOk?: Function;
    cbCancel?: Function;
  }>({});

  const dateFilterOptions = AppDefaultSelectOptions.dateFilter;

  const sortOptions = useMemo((): {
    name: string;
    value: SessionSortType;
  }[] => {
    return [
      {
        name: translate('order_newest_first'),
        value: 'recent',
      },
      {
        name: translate('order_oldest_first'),
        value: 'oldest',
      },
      {
        name: translate('order_session_title'),
        value: 'title',
      },
      {
        name: translate('order_session_title_desc'),
        value: 'titleDesc',
      },
    ];
  }, []);

  const [locations, setLocations] = useState<string[]>([]);

  const hasCrossAccessInTeam = User.isAccessible(
    currentUser,
    currentTeam.id,
    'basic',
    'read',
    true,
  );

  const hasBasicWriteAccess = User.isAccessible(
    currentUser,
    currentTeam.id,
    'basic',
    'write',
    false,
  );

  const shouldHideCsvDownload = currentTeam.teamType == TeamType.SINGLE;

  const getLocations = async () => {
    const { locations, error } = await services.default.session.getLocations(
      currentTeam.id,
    );

    if (error) {
      enqueueSnackbar({
        variant: 'error',
        message: sprintf(
          '%s: %s',
          translate('snackbar_failed_to_get_location_list'),
          error.message,
        ),
      });
      return;
    }

    setLocations(locations);
  };

  const getPlayers = async () => {
    const { players, error } = await services.default.player.getPlayers(
      currentTeam.id,
      {
        pageSize: AppConstants.SEARCH_DEFAULT_BIG_VALUE,
      },
    );
    if (error) {
      enqueueSnackbar({
        variant: 'error',
        message: sprintf(
          '%s: %s',
          translate('snackbar_failed_to_get_player_list'),
          error.message,
        ),
      });
      return;
    }
    setPlayerOptions(
      players.map((x) => {
        return {
          label: x.name,
          id: x.id,
        };
      }),
    );
  };

  const getSessionsAndUpdateList = async () => {
    logger.debug(`Update sessions`);
    const result = await services.default.session.getSessions(currentTeam.id, {
      keyword: conditions.keyword,
      sort: conditions.sort,
      playerId:
        conditions.playerId === ID_OF_ALL_PLAYER
          ? undefined
          : conditions.playerId,
      dateFilter: conditions.filter,
      offset: conditions.currentPage * conditions.rowsPerPage,
      pageSize: conditions.rowsPerPage,
      location: conditions.location,
    });

    if (result.error) {
      setLoadError(result.error);
      return;
    }

    setLoadError(null);
    setSessions(result.sessions);
    setNumberOfTotalItems(result.total);
  };

  const downloadAsCsv = () => {
    const apiUnit: 'm' | 'inch' = unit == 'cm' ? 'm' : 'inch';
    wrapForLoading(setIsCsvDownloading, () => {
      services.default.session.downloadSessionsAsCsv(currentTeam.id, {
        keyword: conditions.keyword,
        sort: conditions.sort,
        playerId:
          conditions.playerId === ID_OF_ALL_PLAYER
            ? undefined
            : conditions.playerId,
        dateFilter: conditions.filter,
        location: conditions.location,
        unit: apiUnit,
      });
    });
  };

  const onDeleteButtonClicked = async (sess: Session) => {
    setConfirmModalDataIsOpen(true);
    setConfirmModalData({
      cbOk: async () => {
        await services.default.session.deleteSession(currentTeam.id, sess.id);
        await getSessionsAndUpdateList();
      },
    });
  };

  const initialize = async () => {
    try {
      await Promise.all([getPlayers(), getLocations()]);
      const parsed = {
        ...parseQueryParam(router.query),
        ...services.localStorage.defaultPaginationData(
          currentUser.id,
          router.query,
        ),
      };
      setConditions({
        ...conditions,
        ...parsed,
      });
      updateQueryParameters({
        ...parsed,
        searchTrigger: new Date(),
      });
    } finally {
      setIsInitialized(true);
    }
  };

  const updateQueryParameters = (
    conds: SessionQueryCondition & CommonPaginationData,
  ) => {
    const param = buildQueryParam(conds);
    PathUtil.routerPushOrReplaceWithPaginationData(
      router,
      conds.currentPage,
      PAGE_INFO.SESSIONS.href(currentTeam.id, param),
    );
  };

  // This must be configured for browser back.
  useEffect(() => {
    if (!isInitialized) {
      return;
    }
    // Important: Call after setConditions to trigger (*1)
    const parsed = parseQueryParam(router.query);
    setConditions({
      ...conditions,
      ...parsed,
      searchTrigger: new Date(),
    });
  }, [router.query]); // browser back -> trigger by paginationData

  useEffect(() => {
    // (*1
    if (!isInitialized) {
      return;
    }
    getSessionsAndUpdateList();
  }, [conditions.searchTrigger]);

  useEffect(() => {
    reloader.reloadIfNeeded();
    initialize();
  }, []);

  return (
    // mbはFABのため
    <Container sx={{ position: 'relative', mb: 10 }}>
      <DefaultBreadCrumbs
        breadcrumbs={[
          {
            name: translate(PAGE_INFO.SESSIONS.name as keyof typeof translate),
            link: PAGE_INFO.SESSIONS.href(currentTeam.id),
          },
        ]}
      />
      <SessionUpdateModal
        teamId={teamId}
        isOpen={isEditSessionModalOpen}
        setIsOpen={setIsEditSessionModalOpen}
        session={editingSession}
        onClose={() => {
          setEditingSession(null);
          setIsEditSessionModalOpen(false);
          getSessionsAndUpdateList();
        }}
      />
      <SessionCreationModal
        teamId={teamId}
        team={currentTeam}
        isOpen={isModalOpen}
        setIsOpen={setIsModalOpen}
        defaultPlayer={null}
        onSessionCreated={async () => {
          getSessionsAndUpdateList();
        }}
        onExitButtonClickedAfterSessionSuccessfullyCreated={async (session) => {
          router.push(
            PAGE_INFO.SESSION_RESOURCES.href(currentTeam.id, session.id, {
              mode: 'upload',
            }),
          );
        }}
      />
      <ConfirmationModal
        isOpen={confirmModalDataIsOpen}
        setIsOpen={setConfirmModalDataIsOpen}
        isDeleteMode={true}
        {...confirmModalData}
        title={translate('delete_session')}
        onClose={() => {
          setConfirmModalDataIsOpen(false);
          setConfirmModalData({});
        }}
      />
      <Typography variant="h1">{translate('all_sessions')}</Typography>
      <Divider sx={{ mt: 1, mb: 5 }} />

      <TeamPlanLimitBand team={currentTeam} />

      <Card sx={{ backgroundColor: 'white', p: 2 }}>
        <Stack
          direction={{ xs: 'column', md: 'row-reverse' }}
          spacing={2}
          justifyContent="space-between"
        >
          <DefaultSearchField
            value={conditions.keyword}
            onSearch={() => {
              const newData = {
                ...conditions,
                currentPage: 0,
              };
              updateQueryParameters(newData);
            }}
            onChange={(e) => {
              setConditions({
                ...conditions,
                keyword: e.target.value,
              });
            }}
          />
          <Grid container direction="row" spacing={1} sx={{ flex: 1 }}>
            <Grid size="auto">
              <FormControl size="small" variant="standard">
                <Select
                  value={conditions.sort}
                  onChange={(e) => {
                    const newData = {
                      ...conditions,
                      sort: e.target.value as SessionSortType,
                      currentPage: 0,
                    };
                    setConditions(newData);
                    updateQueryParameters(newData);
                  }}
                >
                  {sortOptions.map((x) => {
                    return (
                      <MenuItem key={x.value} value={x.value}>
                        {x.name}
                      </MenuItem>
                    );
                  })}
                </Select>
              </FormControl>
            </Grid>
            <Grid size="auto">
              <FormControl size="small" variant="standard">
                <Select
                  value={conditions.filter}
                  onChange={(e) => {
                    const newData = {
                      ...conditions,
                      filter: e.target.value as SessionDateFilterType,
                      currentPage: 0,
                    };
                    setConditions(newData);
                    updateQueryParameters(newData);
                  }}
                >
                  {dateFilterOptions.map((x) => {
                    return (
                      <MenuItem key={x.value} value={x.value}>
                        {translate(x.name as keyof typeof translate)}
                      </MenuItem>
                    );
                  })}
                </Select>
              </FormControl>
            </Grid>
            <Grid size="auto">
              <FormControl size="small" variant="standard">
                <Autocomplete
                  options={playerOptions}
                  value={
                    playerOptions?.find((x) => x.id === conditions.playerId) ??
                    null
                  }
                  isOptionEqualToValue={(a, b) => a.id === b.id}
                  renderInput={(params) => (
                    <TextField
                      {...params}
                      placeholder={translate('all_players')}
                      variant="standard"
                    />
                  )}
                  size="small"
                  onChange={(__, value) => {
                    const newData = {
                      ...conditions,
                      playerId: value?.id ?? null,
                      currentPage: 0,
                    };
                    setConditions(newData);
                    updateQueryParameters(newData);
                  }}
                />
              </FormControl>
            </Grid>
            {locations.length > 0 ? (
              <Grid size="auto">
                <FormControl size="small" variant="standard">
                  <Select
                    value={conditions.location ?? VALUE_FOR_ALL_LOCATIONS}
                    onChange={(e) => {
                      const newData = {
                        ...conditions,
                        location:
                          e.target.value == VALUE_FOR_ALL_LOCATIONS
                            ? null
                            : (e.target.value as string),
                        currentPage: 0,
                      };
                      setConditions(newData);
                      updateQueryParameters(newData);
                    }}
                  >
                    <MenuItem value={VALUE_FOR_ALL_LOCATIONS}>
                      {translate('all_locations')}
                    </MenuItem>
                    {locations.map((x) => {
                      return (
                        <MenuItem key={x} value={x}>
                          {x === '' ? '-' : x}
                        </MenuItem>
                      );
                    })}
                  </Select>
                </FormControl>
              </Grid>
            ) : (
              ''
            )}
          </Grid>
        </Stack>

        {loadError ? (
          <CriticalError error={loadError} />
        ) : (
          <SessionSearchResultTable
            user={currentUser}
            teamId={teamId}
            sessions={sessions}
            onEditButtonClicked={(sess) => {
              setEditingSession(sess);
              setIsEditSessionModalOpen(true);
            }}
            onDeleteButtonClicked={onDeleteButtonClicked}
          />
        )}
        {!shouldHideCsvDownload && (
          <Box display="flex" justifyContent="flex-end">
            <Button
              loading={isCsvDownloading}
              variant="contained"
              onClick={() => downloadAsCsv()}
            >
              {translate('download_csv')}
            </Button>
          </Box>
        )}

        <CommonPagination
          user={currentUser}
          numberOfTotalItems={numberOfTotalItems}
          commonPaginationData={{
            currentPage: conditions.currentPage,
            rowsPerPage: conditions.rowsPerPage,
          }}
          onChange={(data) => {
            updateQueryParameters({
              ...conditions,
              ...data,
            });
          }}
        />
      </Card>
      {hasBasicWriteAccess && (
        <FloatingButton
          icon={<EditCalendar />}
          title={translate('create_new_session')}
          onClick={() => setIsModalOpen(true)}
        />
      )}
    </Container>
  );
}

export default function Page() {
  const { router } = useServicesHook();
  const currentUser = useSelector((state) => state.user.me);
  const teams = useSelector((state) => state.user.accessibleTeams);
