  // https://knowhere-org.slack.com/archives/C03EGR0M9AN/p1759381143908219
  const shouldHideUpload = isStagingOrProductionSingleTeam(currentTeam);
  const shouldHideCsvDownload = currentTeam.teamType == TeamType.SINGLE;

  const [isFileUploadModalOpen, setIsFileUploadModalOpen] = useState<boolean>(
    mode == 'upload',
  );

