import {
  Body,
  Controller,
  Get,
  Logger,
  Param,
  ParseUUIDPipe,
  Post,
  Put,
  Req,
  UseGuards,
} from '@nestjs/common';
import { ApiOperation } from '@nestjs/swagger';

import {
  ApiDefault,
  Authorized,
  Coded,
  CodedMethod,
} from '@/app/common/decorators';
import { AppExtendedRequest } from '@/app/common/types';
import { ValidationUtil } from '@/app/common/utils/validation.util';
import { BaseController } from '@/app/controllers/base-controller';
import { CodedForbiddenException } from '@/app/exceptions/errors/coded-forbidden.exception';
import { ErrorInfo } from '@/app/exceptions/errors/error-info';
import { SelfAccessGuard } from '@/app/guards/self-access.guard';
import { TeamAccessGuard } from '@/app/guards/team-access.guard';
import {
  EditUserRoleDto,
  editUserRoleDtoValidator,
  InviteUserDto,
  inviteUserDtoValidator,
  UserSearchDto,
  userSearchDtoValidator,
} from '@/app/models/dto/user.dto';
import { UsersService } from '@/app/services/users.service';

@Coded('CTUS')
@ApiDefault()
@Authorized()
@Controller('teams/:teamId/users')
export class TeamUsersController extends BaseController {
  private readonly logger = new Logger(TeamUsersController.name);

  constructor(private readonly usersService: UsersService) {
    super();
  }

  static ERROR_CODES = {
    USER_OWN_STATUS_CANNNOT_BE_CHANGED: ErrorInfo.getBuilder(
      'UOSC',
      'user_own_status_cannot_be_changed',
    ),
    INVALID_ROLE: ErrorInfo.getBuilder('IR', 'invalid_role_for_this_user'),
  };

  get EC() {
    return TeamUsersController.ERROR_CODES;
  }

  @ApiOperation({
    summary: '[team][management,admin] Edits roles of a user',
    description: '',
    tags: ['team-management'],
  })
  @UseGuards(new TeamAccessGuard('management', 'admin'))
  @Put(':userId/user-roles')
  @CodedMethod('EUSR')
  async editUserRole(
    @Req() req: AppExtendedRequest,
    @Param('teamId', ParseUUIDPipe) targetTeamId: string,
    @Param('userId', ParseUUIDPipe) targetUserId: string,
    @Body() dto: EditUserRoleDto,
  ) {
    const cbuilder = this.getCodeBuilder();
    const { roleChecker } = req.appExtension.auth!;
    const validated = await ValidationUtil.validate(
      editUserRoleDtoValidator(),
      dto,
    );

    // super_admin role is given only by super_admin
    if (
      validated.role === 'super_admin' &&
      !roleChecker.checkForSuperUser('management', 'admin')
    ) {
      throw new CodedForbiddenException(
        this.code,
        this.EC.INVALID_ROLE(cbuilder.build()),
      );
    }

    const { user } = await this.usersService.editUserRole(
      targetTeamId,
      targetUserId,
      validated.role,
    );

    return {
      user,
    };
  }

  @ApiOperation({
    summary: '[team][management,admin] Invites a user to a team',
    description: '',
    tags: ['team-management'],
  })
  @UseGuards(new TeamAccessGuard('management', 'admin'))
  @Post('invite')
  @CodedMethod('IVUS')
  async inviteUser(
    @Req() req: AppExtendedRequest,
    @Param('teamId', ParseUUIDPipe) targetTeamId: string,
    @Body() dto: InviteUserDto,
  ) {
    const cbuilder = this.getCodeBuilder();
    const { requesterUid } = req.appExtension.auth!;

    const validated = await ValidationUtil.validate(
      inviteUserDtoValidator(),
      dto,
    );

    const result = await this.usersService.inviteUser(
      targetTeamId,
      validated.email,
      validated.role,
      validated.userName,
      validated.redirectTo ?? null,
      requesterUid,
      {
        lang:
          req.headers['accept-language'] ??
          req.headers['content-language'] ??
          null,
      },
    );

    return {
      user: result.user,
    };
  }

  @ApiOperation({
    summary: '[team][management,admin] Deactivates a user',
    description: '',
    tags: ['team-management'],
  })
  @Put(':userId/deactivate')
  @UseGuards(new TeamAccessGuard('management', 'admin'))
  @CodedMethod('DUS')
  async deactivateUser(
    @Req() req: AppExtendedRequest,
    @Param('teamId', ParseUUIDPipe) targetTeamId: string,
    @Param('userId', ParseUUIDPipe) targetUserId: string,
  ) {
    const cbuilder = this.getCodeBuilder();
    const { requesterUid } = req.appExtension.auth!;

    if (requesterUid == targetUserId) {
      // the users own status cannot be changed
      throw new CodedForbiddenException(
        this.code,
        this.EC.USER_OWN_STATUS_CANNNOT_BE_CHANGED(cbuilder.build()),
      );
    }

