import { ExecutionContext, Logger } from '@nestjs/common';
import _ from 'lodash';
import { Observable } from 'rxjs';

import { Coded, CodedMethod } from '@/app/common/decorators';
import { AppExtendedRequest } from '@/app/common/types';
import { StringUtil } from '@/app/common/utils/string.util';
import { CodedForbiddenException } from '@/app/exceptions/errors/coded-forbidden.exception';
import { ErrorInfo } from '@/app/exceptions/errors/error-info';
import { RoleDomain, RoleLevel } from '@/app/models/role';

import { BaseGuard } from './base.guard';

/**
 * Restrict access to teams.
 * The API path including 'teams/:teamId' must be restricted only for the members belonging to the team or super admins.
 */
@Coded('GTAC')
export class TeamAccessGuard extends BaseGuard {
  private readonly logger = new Logger(TeamAccessGuard.name);

  constructor(
    private readonly domain: RoleDomain,
    private readonly level: RoleLevel,
  ) {
    super();
  }

  static ERROR_CODES = {
    INVALID_ROLE: ErrorInfo.getBuilder('IR', 'invalid_role_for_this_user'),
    INVALID_TEAM_ID: ErrorInfo.getBuilder('IVTI', 'invalid_team_id'),
  };

  get EC() {
    return TeamAccessGuard.ERROR_CODES;
  }

  @CodedMethod('CA')
  canActivate(
    context: ExecutionContext,
  ): boolean | Promise<boolean> | Observable<boolean> {
    const cbuilder = this.getCodeBuilder();
    const request = context.switchToHttp().getRequest<AppExtendedRequest>();

    const { roleChecker } = request.appExtension.auth!;
    const paramTeamId = request.params.teamId;

    // NOTE: TeamAccessGuard does not check the accessibility about userIds.
    if (!roleChecker.check(paramTeamId, this.domain, this.level, false)) {
      // no domain-matched roles
      throw new CodedForbiddenException(
        this.code,
        this.EC.INVALID_ROLE(cbuilder.build()),
      );
    }

    if (!StringUtil.isValidUUID(paramTeamId)) {
      throw new CodedForbiddenException(
        this.code,
        this.EC.INVALID_TEAM_ID(cbuilder.build()),
      );
    }

    return true;
  }
}

