import _ from 'lodash';
import { ZodError } from 'zod';

import { Coded } from '@/models/types';

import { HttpError } from './http-error';

export class ServiceError extends Error implements Coded {
  readonly validations: Record<string, any> = {};
  constructor(
    readonly error: Error, // (ZodError | HttpError | other error)
  ) {
    super();
    if (error instanceof ZodError) {
      // validation, frontend
      for (const e of error.errors ?? []) {
        _.set(this.validations, e.path, e);
      }
    } else if (error instanceof HttpError) {
      // validation, api
      this.validations = error.validation;
      // critical, api
      this.message = HttpError.buildErrorMessage(error);
    } else {
      const suffix = this.code ? ` [${this.code}]` : '';
      this.message = `${error.message}${suffix}`;
    }
  }

  get code(): string | null {
    return _.get(this.error, 'code', null);
  }
}

