   128→  async wrapForApiError<T>(req: () => Promise<AxiosResponse<T, any>>): Promise<{
   129→    result: T | null;
   130→    errors: any | null;
   131→  }> {
   132→    let result: AxiosResponse<T, any> | null = null;
   133→    let errors: any | null = null;
   134→
   135→    try {
   136→      result = await req();
   137→    } catch (error: any) {
   138→      if (error?.status == 404) {
   139→        logger.warn(error?.message);
   140→      } else {
   141→        logger.error(error);
   142→      }
   143→      errors = this.extract(error);
   144→    }
   145→
   146→    return {
   147→      result: result?.data ?? null,
   148→      errors: errors,
   149→    };
   150→  }
   151→
   152→  extract(error: AxiosError): ServiceError {
   153→    const response: AxiosResponse<any, any> | undefined = error?.response;
   154→    const errors: {
   155→      errorCode: string | null;
   156→      validation: Record<string, ValidationError>;
   157→      others: ApiErrorInfo[];
   158→    } = {
   159→      errorCode: null,
   160→      validation: {},
   161→      others: [],
   162→    };
   163→    if (!response || response.status < 400) {
   164→      // no response or error with status < 400
