import _ from 'lodash';

export interface ApiErrorInfo {
  message: string | null;
  translated: string | null;
}

export class HttpError extends Error {
  constructor(
    readonly errorCode: string | null,
    readonly validation: Record<string, ApiErrorInfo>,
    readonly others: ApiErrorInfo[],
  ) {
    super();
  }

  /**
   * (Translated message) [ERROR-CODE]
   * e.g. "Invalid user ID [E-CUS-GU-XXX-001]" or "不正なユーザIDです [E-CUS-GU-XXX-001]"
   */
  static buildErrorMessage(err: HttpError) {
    const otherMessage = _.first(err.others);
    if (!otherMessage) {
      return '';
    }
    return `${otherMessage.translated}${err.errorCode ? ` [${err.errorCode}]` : ''}`;
  }
}

