import { Box, Typography } from '@mui/material';
import _ from 'lodash';
import { normalizePathTrailingSlash } from 'next/dist/client/normalize-trailing-slash';
import { getClientBuildManifest } from 'next/dist/client/route-loader';
import { denormalizePagePath } from 'next/dist/shared/lib/page-path/denormalize-page-path';
import { isDynamicRoute } from 'next/dist/shared/lib/router/utils/is-dynamic';
import { parseRelativeUrl } from 'next/dist/shared/lib/router/utils/parse-relative-url';
import { getRouteRegex } from 'next/dist/shared/lib/router/utils/route-regex';
import Link from 'next/link';
import { NextRouter } from 'next/router';
import React, { ReactElement, useEffect, useState } from 'react';

import { PAGE_INFO } from '@/constants/page.constants';
import useServicesHook from '@/hooks';

async function getDoesLocationMatchPage(location: string) {
  const pages = await getPageList();
  const parsed = parseRelativeUrl(location);
  const { pathname } = parsed;
  return pathMatchesPage(pathname, pages);
}

async function getPageList() {
  if (process.env.NODE_ENV === 'production') {
    const { sortedPages } = await getClientBuildManifest();
    return sortedPages;
  } else {
    if (typeof window !== 'undefined' && window.__DEV_PAGES_MANIFEST) {
      return window.__DEV_PAGES_MANIFEST.pages;
    }
  }
  return [];
}

function pathMatchesPage(pathname: string, pages: string[]) {
  const cleanPathname = normalizePathTrailingSlash(
    denormalizePagePath(pathname),
  );

  if (pages.includes(cleanPathname)) {
    return true;
  }

  const page = pages.find((page) => {
    return isDynamicRoute(page) && getRouteRegex(page).re.test(cleanPathname);
  });
  if (page) {
    return true;
  }

  return false;
}

function weAreLost(router: NextRouter) {
  return router.pathname !== router.asPath;
}

export default function Page() {
  const { router } = useServicesHook();
  const [isNotFound, setIsNotFound] = useState(false);

  const [isChecked, setIsChecked] = useState<boolean>(false);

  const processLocationAndRedirect = async (router: NextRouter) => {
    if (weAreLost(router)) {
      const targetIsValidPage = await getDoesLocationMatchPage(router.asPath);
      if (targetIsValidPage) {
        // パスワードリセット時の特殊な遷移。
        // cloudfront+s3で動かすと、supabaseからのコールバックのurlがなぜか開けないための処理。
        // ここでも遷移しない場合があるので、isCheckedで画面にリンクを出すようにした。
        setIsChecked(true);
        if (
          _.startsWith(
            router.asPath,
            PAGE_INFO.RECOVER_BY_EMAIL_CALLBACK.href(),
          )
        ) {
          await router.replace(PAGE_INFO.RESET_PASSWORD.href());
          return;
        }
        if (_.startsWith(router.asPath, PAGE_INFO.SIGN_IN.href())) {
          await router.replace(PAGE_INFO.SIGN_IN.href());
          return;
        }

        await router.replace(router.asPath);
        return;
      }
    }
    setIsNotFound(true);
  };

  useEffect(() => {
    if (router.isReady) {
      processLocationAndRedirect(router);
    }
  }, [router.isReady]);

  if (!isNotFound) {
    return (
      <>
        {isChecked ? (
          <Link href={router.asPath}>
            画面が遷移しない場合はこちらをクリックしてください。
          </Link>
        ) : (
          ''
        )}
      </>
    );
  }

  return (
    <Box sx={{ pt: 8 }}>
      <Typography variant="h1">(404) Page Not Found.</Typography>

      <Box>
        <Link href={PAGE_INFO.TOP.href()}>Open Top Page.</Link>
      </Box>
    </Box>
  );
}

Page.getLayout = function getLayout(page: ReactElement) {
  return <Box sx={{ m: 10 }}>{page}</Box>;
};

