import type { PayloadAction } from '@reduxjs/toolkit';
import { createSlice } from '@reduxjs/toolkit';
import _ from 'lodash';

import { SupportedUnit } from '@/constants/app.constants';
import { Team } from '@/models/team';
import { User } from '@/models/user';
import { UserRole } from '@/models/user-role';
import { ServiceError } from '@/services/errors/service-error';
import { logger } from '@/utils/logger';

interface UserDataState {
  me: User | null;
  accessibleTeams: Team[];
  currentTeam: Team | null;
  error: ServiceError | null;
  loginStatus: 'unknown' | 'yes' | 'no' | 'error' | 'initial';
  unit: SupportedUnit;
}

const initialState: UserDataState = {
  me: null,
  accessibleTeams: [],
  currentTeam: null,
  error: null,
  loginStatus: 'initial',
  unit: 'cm',
};

const slice = createSlice({
  name: 'user',
  initialState,
  reducers: {
    setUser(state: UserDataState, action: PayloadAction<User | null>): void {
      state.me = action.payload;
    },
    setUserWithLoginStatus(
      state: UserDataState,
      action: PayloadAction<{ user: User | null; error: ServiceError | null }>,
    ): void {
      state.me = action.payload.user;
      state.error = action.payload.error;
      state.loginStatus = action.payload.error
        ? 'error'
        : action.payload.user
          ? 'yes'
          : 'no';
      //
      // const lsService = new LocalStorageService()
      // const localData = lsService.getAll()
      logger.info(`Login status updated: ${state.loginStatus}`);
    },
    setTeams(
      state: UserDataState,
      action: PayloadAction<{
        teams: Team[];
        teamId?: string | null;
        teamIdToUserRoles?: Record<string, UserRole[]>;
        isSuperAdminMode?: boolean;
      }>,
    ): void {
      state.accessibleTeams = action.payload.teams;
      const newTeamId = action.payload.teamId ?? state.currentTeam?.id;
      const ur = action.payload.teamIdToUserRoles;
      const validTeams =
        ur && !action.payload.isSuperAdminMode
          ? state.accessibleTeams.filter((t) => {
              return _.some(ur[t.id], (r) => r.deleteFlag === false);
            })
          : state.accessibleTeams;
      state.currentTeam =
        validTeams.find((x) => x.id == newTeamId) ??
        _.first(validTeams) ??
        null;
      logger.debug(
        `Teams updated: ID=${state.currentTeam?.id}, name=${state.currentTeam?.name}`,
      );
    },
    setCurrentTeam(
      state: UserDataState,
      action: PayloadAction<{ teamId: string }>,
    ): void {
      const validTeams = state.accessibleTeams.filter((t) => {
        return _.some(
          state.me?.givenUserRoles[t.id] ?? [],
          (r) => r.deleteFlag === false,
        );
      });
      const foundTeam = state.accessibleTeams.find(
        (x) => x.id == action.payload.teamId,
      );
      state.currentTeam = foundTeam ?? state.currentTeam;
      logger.debug(
        `Team updated: ID=${state.currentTeam?.id}, name=${state.currentTeam?.name}`,
      );
    },
    setUnit(
      state: UserDataState,
      action: PayloadAction<{ unit: SupportedUnit }>,
    ): void {
      state.unit = action.payload.unit;
    },
  },
});

export const { reducer, actions } = slice;

