import { fetchAuthSession } from 'aws-amplify/auth';
import axios, {
  AxiosError,
  AxiosInstance,
  AxiosRequestConfig,
  AxiosResponse,
} from 'axios';
import _ from 'lodash';
import moment from 'moment';

import AppConstants from '@/constants/app.constants';
import { EnvManager } from '@/constants/env.constants';
import { MandatoryOrHavingError } from '@/models/types';
import { CodedSystemError } from '@/services/errors/coded-system-error';
import { ApiErrorInfo, HttpError } from '@/services/errors/http-error';
import { ServiceError } from '@/services/errors/service-error';
import { ValidationError } from '@/services/errors/validation-error';
import { LocalStorageService } from '@/services/local-storage/local-storage.service';
import { snakizeKeys } from '@/utils/functions/transformer';
import { getDefaultLanguage, translate } from '@/utils/i18n';
import { logger } from '@/utils/logger';

/**
 * 今のところ使うかは未定だが、RESTの通常APIサーバなどへの一般的なhttpコールを行う際には用いる
 * TODO: もしgraphqlなどを使う場合には別途定義した方がいい
 */
export abstract class ApiClient {
  private static _client: AxiosInstance | null = null;
  private static _localStorage: LocalStorageService | null = null;
  protected readonly client: AxiosInstance;

  constructor() {
    if (!ApiClient._client) {
      throw Error('The client has not initialized yet.');
    }
    this.client = ApiClient._client;
  }

  static initialize(axiosOpts: AxiosRequestConfig) {
    if (ApiClient._client) {
      logger.warn('The HTTP client has already initialized.');
      return;
    }
    ApiClient._localStorage = new LocalStorageService();
    ApiClient._client = ApiClient.getAxiosInstance(
      axiosOpts,
      ApiClient._localStorage,
    );
  }

  /**
   * Axiosのインスタンス（http問い合わせ用）を取得する。
   * 内部的に自動でcamelcase/snakecaseの変換や認証情報の付与を行うようにしており、注意が必要。
   * @param {any} axiosOpts
   * @returns
   */
  private static getAxiosInstance(
    axiosOpts: AxiosRequestConfig,
    localStorage: LocalStorageService,
  ) {
    const Axios = axios.create(axiosOpts);

    Axios.interceptors.request.use(
      async (config) => {
        // APIのversion管理をどうするかというのは要相談。以下のようにヘッダに入れるのがおすすめ
        // _.set(config.headers ?? {}, AppConstants.API_VERSION_HEADER, AppConstants.API_VERSION)

        // Cognito
        const authSession = await fetchAuthSession();
        // logger.debug(`cognito access token: ${authSession.tokens?.accessToken.toString()}`)
        const token = authSession.tokens?.accessToken.toString();

        if (token && config.withCredentials) {
          config.headers['Authorization'] = 'Bearer ' + token;
        }

        const lang = localStorage.getLanguage(null) ?? getDefaultLanguage();
        config.headers['Accept-Language'] = lang;
        if (this.isApiServerRequest(config)) {
          config.headers['X-Api-Version'] = '1.1';
        }

        return config;
      },
      (error) => {
        return Promise.reject(error);
      },
    );

    Axios.interceptors.response.use(
      (response) => {
        return response;
      },
      (error) => {
        // 403 Forbidden エラーの場合、access-denied ページにリダイレクト
        if (error?.response?.status === 403) {
          // クライアントサイドでのリダイレクトのみ（SSRでは実行しない）
          if (typeof window !== 'undefined') {
            const currentPath = window.location.pathname;
            // すでに access-denied ページにいる場合は無限ループを避ける
            if (currentPath !== '/access-denied') {
              window.location.href = '/access-denied';
            }
          }
        }
        return Promise.reject(error);
      },
    );
    return Axios;
  }

  /**
   * リクエスト先がAPIサーバのURLかどうかを返す。
   */
  private static isApiServerRequest(config: AxiosRequestConfig) {
    const requestUrl = axios.getUri(config);
    return requestUrl.startsWith(`${apiBaseUrl}/`);
  }

  static convertTypes(data: any, depth = 1): any {
    if (_.isDate(data)) {
      return moment(data).format(AppConstants.API_DATETIME_FORMAT);
    }
    if (_.isArray(data)) {
      return _.map(data, (x) => this.convertTypes(x, depth + 1));
    }
    if (_.isObject(data)) {
      return _.transform(
        data,
        (memo: any, val, key: string) => {
          memo[key] = this.convertTypes(val, depth + 1);
        },
        {},
      );
    }
    return data;
  }

  async wrapForApiError<T>(req: () => Promise<AxiosResponse<T, any>>): Promise<{
    result: T | null;
    errors: any | null;
  }> {
    let result: AxiosResponse<T, any> | null = null;
    let errors: any | null = null;

    try {
      result = await req();
    } catch (error: any) {
      if (error?.status == 404) {
        logger.warn(error?.message);
      } else {
        logger.error(error);
      }
      errors = this.extract(error);
    }

    return {
      result: result?.data ?? null,
      errors: errors,
    };
  }

  extract(error: AxiosError): ServiceError {
    const response: AxiosResponse<any, any> | undefined = error?.response;
    const errors: {
      errorCode: string | null;
      validation: Record<string, ValidationError>;
      others: ApiErrorInfo[];
    } = {
      errorCode: null,
      validation: {},
      others: [],
    };
    if (!response || response.status < 400) {
      // no response or error with status < 400
      if (error.code == 'ECONNABORTED') {
        return new ServiceError(
          new CodedSystemError(
            // FrontSide-?-EXtract-001
            'FS',
            'UK',
            'EX-001',
            response?.data?.translated ?? translate('error_connection_timeout'),
          ),
        );
      } else if (error.code == 'ETIMEDOUT') {
        return new ServiceError(
          new CodedSystemError(
            // FrontSide-?-EXtract-002
            // https://github.com/axios/axios/blob/21a5ad34c4a5956d81d338059ac0dd34a19ed094/README.md?plain=1#L549
            'FS',
            'UK',
            'EX-002',
            response?.data?.translated ?? translate('error_connection_timeout'),
          ),
        );
      } else if (error.code == 'ERR_NETWORK') {
        return new ServiceError(
          new CodedSystemError(
            // FrontSide-?-EXtract-003
            'FS',
            'UK',
            'EX-003',
            response?.data?.translated ?? translate('error_network'),
          ),
        );
      }
      return new ServiceError(
        new CodedSystemError(
          // FrontSide-?-EXtract-004
          'FS',
          'UK',
          'EX-004',
          response?.data?.translated ??
            translate('error_network') + ` (${error.code})`,
        ),
      );
    }
    // build HttpError with 'errors'
    if (response.status === 422) {
      // Validations
      errors.validation = {};
      _.each(response.data?.errors, (v, k) => {
        _.set(errors.validation, v.param, v);
      }) ?? {};
    } else {
      // others
      // FrontSide-?-EXtract-002
      const code = response.data?.code ?? 'E-FS-UK-EX-002';
      errors.errorCode = code;
      errors.others.push({
        message: response.data?.message ?? null,
        translated: response.data?.translated ?? null,
      });
    }
    return new ServiceError(
      new HttpError(
        errors.errorCode,
        errors.validation,
        errors.others,
        response.status,
      ),
    );
  }

  adjustApiResultForMandatoryObject<T extends string, S>(
    key: T,
    data: S | null,
    errors: ServiceError | null,
  ): MandatoryOrHavingError<T, S> {
    return data && !errors
      ? {
          [key]: data,
          error: null,
        }
      : {
          [key]: null,
          error: errors ?? new ServiceError(new Error('E-CL-ND-AR-001')),
        };
  }
}

const apiBaseUrl = new URL('api', EnvManager.config.API_HOST).toString();

ApiClient.initialize({
  baseURL: apiBaseUrl,
  timeout: AppConstants.API_TIMEOUT_MILLIS,
  withCredentials: true,
});

