import { fetchAuthSession } from 'aws-amplify/auth';
import axios, {
  AxiosError,
  AxiosInstance,
  AxiosRequestConfig,
  AxiosResponse,
} from 'axios';
import _ from 'lodash';
import moment from 'moment';

import AppConstants from '@/constants/app.constants';
import { EnvManager } from '@/constants/env.constants';
import { MandatoryOrHavingError } from '@/models/types';
import { CodedSystemError } from '@/services/errors/coded-system-error';
import { ApiErrorInfo, HttpError } from '@/services/errors/http-error';
import { ServiceError } from '@/services/errors/service-error';
import { ValidationError } from '@/services/errors/validation-error';
import { LocalStorageService } from '@/services/local-storage/local-storage.service';
import { snakizeKeys } from '@/utils/functions/transformer';
import { getDefaultLanguage, translate } from '@/utils/i18n';
import { logger } from '@/utils/logger';

/**
 * 今のところ使うかは未定だが、RESTの通常APIサーバなどへの一般的なhttpコールを行う際には用いる
 * TODO: もしgraphqlなどを使う場合には別途定義した方がいい
 */
export abstract class ApiClient {
  private static _client: AxiosInstance | null = null;
  private static _localStorage: LocalStorageService | null = null;
  protected readonly client: AxiosInstance;

  constructor() {
    if (!ApiClient._client) {
      throw Error('The client has not initialized yet.');
    }
    this.client = ApiClient._client;
  }

  static initialize(axiosOpts: AxiosRequestConfig) {
    if (ApiClient._client) {
      logger.warn('The HTTP client has already initialized.');
      return;
    }
    ApiClient._localStorage = new LocalStorageService();
    ApiClient._client = ApiClient.getAxiosInstance(
      axiosOpts,
      ApiClient._localStorage,
    );
  }

  /**
   * Axiosのインスタンス（http問い合わせ用）を取得する。
   * 内部的に自動でcamelcase/snakecaseの変換や認証情報の付与を行うようにしており、注意が必要。
   * @param {any} axiosOpts
   * @returns
   */
  private static getAxiosInstance(
    axiosOpts: AxiosRequestConfig,
    localStorage: LocalStorageService,
  ) {
    const Axios = axios.create(axiosOpts);

    Axios.interceptors.request.use(
      async (config) => {
        // APIのversion管理をどうするかというのは要相談。以下のようにヘッダに入れるのがおすすめ
        // _.set(config.headers ?? {}, AppConstants.API_VERSION_HEADER, AppConstants.API_VERSION)

        // Cognito
        const authSession = await fetchAuthSession();
        // logger.debug(`cognito access token: ${authSession.tokens?.accessToken.toString()}`)
        const token = authSession.tokens?.accessToken.toString();

        if (token && config.withCredentials) {
          config.headers['Authorization'] = 'Bearer ' + token;
        }

        const lang = localStorage.getLanguage(null) ?? getDefaultLanguage();
        config.headers['Accept-Language'] = lang;
        if (this.isApiServerRequest(config)) {
          config.headers['X-Api-Version'] = '1.1';
        }

        return config;
      },
      (error) => {
        return Promise.reject(error);
      },
    );

    Axios.interceptors.response.use(
      (response) => {
        return response;
      },
      async (error) => {
        // 403 Forbidden エラーの場合、グローバル状態を更新
        if (error?.response?.status === 403) {
          // クライアントサイドでのみ実行（SSRでは実行しない）
          if (typeof window !== 'undefined') {
            const { getGlobalDispatch } = await import(
              '@/store/global-dispatch'
            );
            const { actions } = await import('@/store/slices/error.slice');
            const dispatch = getGlobalDispatch();
            if (dispatch) {
              dispatch(actions.setForbiddenError(true));
            }
          }
        }
        return Promise.reject(error);
      },
    );
    return Axios;
  }

  /**
   * リクエスト先がAPIサーバのURLかどうかを返す。
   */
  private static isApiServerRequest(config: AxiosRequestConfig) {
    const requestUrl = axios.getUri(config);
    return requestUrl.startsWith(`${apiBaseUrl}/`);
  }

  static convertTypes(data: any, depth = 1): any {
    if (_.isDate(data)) {
      return moment(data).format(AppConstants.API_DATETIME_FORMAT);
    }
    if (_.isArray(data)) {
      return _.map(data, (x) => this.convertTypes(x, depth + 1));
    }
    if (_.isObject(data)) {
      return _.transform(
        data,
        (memo: any, val, key: string) => {
          memo[key] = this.convertTypes(val, depth + 1);
        },
        {},
      );
    }
    return data;
  }

  async wrapForApiError<T>(req: () => Promise<AxiosResponse<T, any>>): Promise<{
    result: T | null;
    errors: any | null;
  }> {
    let result: AxiosResponse<T, any> | null = null;
    let errors: any | null = null;

    try {
      result = await req();
    } catch (error: any) {
      if (error?.status == 404) {
        logger.warn(error?.message);
      } else {
        logger.error(error);
      }
      errors = this.extract(error);
    }

    return {
      result: result?.data ?? null,
      errors: errors,
    };
  }

  extract(error: AxiosError): ServiceError {
    const response: AxiosResponse<any, any> | undefined = error?.response;
    const errors: {
      errorCode: string | null;
      validation: Record<string, ValidationError>;
      others: ApiErrorInfo[];
    } = {
      errorCode: null,
      validation: {},
      others: [],
    };
    if (!response || response.status < 400) {
      // no response or error with status < 400
      if (error.code == 'ECONNABORTED') {
        return new ServiceError(
          new CodedSystemError(
            // FrontSide-?-EXtract-001
            'FS',
            'UK',
            'EX-001',
            response?.data?.translated ?? translate('error_connection_timeout'),
          ),
        );
      } else if (error.code == 'ETIMEDOUT') {
        return new ServiceError(
          new CodedSystemError(
            // FrontSide-?-EXtract-002
            // https://github.com/axios/axios/blob/21a5ad34c4a5956d81d338059ac0dd34a19ed094/README.md?plain=1#L549
            'FS',
            'UK',
            'EX-002',
            response?.data?.translated ?? translate('error_connection_timeout'),
          ),
        );
      } else if (error.code == 'ERR_NETWORK') {
        return new ServiceError(
          new CodedSystemError(
            // FrontSide-?-EXtract-003
            'FS',
            'UK',
            'EX-003',
            response?.data?.translated ?? translate('error_network'),
          ),
        );
      }
      return new ServiceError(
        new CodedSystemError(
          // FrontSide-?-EXtract-004
          'FS',
          'UK',
          'EX-004',
          response?.data?.translated ??
            translate('error_network') + ` (${error.code})`,
        ),
      );
    }
    // build HttpError with 'errors'
    if (response.status === 422) {
      // Validations
      errors.validation = {};
      _.each(response.data?.errors, (v, k) => {
        _.set(errors.validation, v.param, v);
      }) ?? {};
    } else {
      // others
      // FrontSide-?-EXtract-002
      const code = response.data?.code ?? 'E-FS-UK-EX-002';
      errors.errorCode = code;
      errors.others.push({
        message: response.data?.message ?? null,
        translated: response.data?.translated ?? null,
      });
    }
    return new ServiceError(
      new HttpError(
        errors.errorCode,
        errors.validation,
        errors.others,
        response.status,
      ),
    );
  }

  adjustApiResultForMandatoryObject<T extends string, S>(
    key: T,
    data: S | null,
    errors: ServiceError | null,
  ): MandatoryOrHavingError<T, S> {
    return data && !errors
      ? {
          [key]: data,
          error: null,
        }
      : {
          [key]: null,
          error: errors ?? new ServiceError(new Error('E-CL-ND-AR-001')),
        };
  }
}

const apiBaseUrl = new URL('api', EnvManager.config.API_HOST).toString();

ApiClient.initialize({
  baseURL: apiBaseUrl,
  timeout: AppConstants.API_TIMEOUT_MILLIS,
  withCredentials: true,
});

content.text:
良い質問ですね！Flutter エンジニアの視点から説明します。まず、考えられる複数のアプローチを示し、その後で Redux と Context の比較をします。

## 実装アプローチの選択肢

### 1. **React Context（現在の実装）**
```typescript
// Context で状態管理
const AccessDeniedContext = createContext<...>()
```

**Flutter での類似概念**: `InheritedWidget` や `Provider` パッケージ
- Widget ツリー全体で状態を共有
- `context.watch<T>()` や `Provider.of<T>(context)` に相当

### 2. **Redux（以前の実装）**
```typescript
// Redux store で状態管理
const errorSlice = createSlice({...})
```

**Flutter での類似概念**: `BLoC` パターンや `Riverpod` の StateNotifier
- グローバルな状態管理
- `BlocProvider` + `BlocBuilder` に相当

### 3. **Axios Response Interceptor + カスタムイベント**
```typescript
// カスタムイベントを発火
window.dispatchEvent(new CustomEvent('accessDenied'))

// アプリ側でリスナー登録
useEffect(() => {
  const handler = () => setShowAccessDenied(true)
  window.addEventListener('accessDenied', handler)
  return () => window.removeEventListener('accessDenied', handler)
}, [])
```

**Flutter での類似概念**: `StreamController` + `StreamBuilder`
- イベントストリームでコンポーネント間通信
- Dart の `Stream` と `StreamSubscription` に相当

### 4. **Higher-Order Component (HOC) パターン**
```typescript
// 各ページを HOC でラップ
function withAccessDeniedCheck(Component) {
  return function WrappedComponent(props) {
    const [hasError, setHasError] = useState(false)
    // エラーチェックロジック
    return hasError ? <AccessDenied /> : <Component {...props} />
  }
}

export default withAccessDeniedCheck(MyPage)
```

**Flutter での類似概念**: Widget の合成パターン
- `Builder` widget や custom wrapper widget に相当

### 5. **React Error Boundary（限定的）**
```typescript
class ErrorBoundary extends React.Component {
  static getDerivedStateFromError(error) {
    if (error.statusCode === 403) {
      return { hasError: true }
    }
  }
  render() {
    if (this.state.hasError) return <AccessDenied />
    return this.props.children
  }
}
```

**制約**: Axios のエラーは非同期で発生するため Error Boundary では直接キャッチできない

### 6. **Next.js Middleware（サーバーサイド）**
```typescript
// middleware.ts
export function middleware(request: NextRequest) {
  // サーバー側で 403 をチェック
  // /access-denied にリダイレクト
}
```

**Flutter での類似概念**: HTTP interceptor や Dio の Interceptor
- ただし Next.js Middleware はサーバーサイドで実行される点が異なる

### 7. **SWR/React Query の onError グローバルハンドラー**
```typescript
// SWR のグローバル設定
<SWRConfig value={{
  onError: (error) => {
    if (error.statusCode === 403) {
      // グローバル処理
    }
  }
}}>
```

**Flutter での類似概念**: `http` パッケージのグローバルインターセプター
- API クライアントレベルでのエラーハンドリング

## Redux vs Context の多角的比較

Flutter の状態管理と対比しながら説明します。

### 📊 比較表

| 観点 | Redux | Context | Flutter での類似 |
|------|-------|---------|------------------|
| **学習曲線** | 急（概念が多い） | 緩（シンプル） | BLoC（急）vs Provider（緩） |
| **ボイラープレート** | 多い | 少ない | BLoC（多）vs Riverpod（少） |
| **パフォーマンス** | 最適化しやすい | 再レンダリングに注意 | `select` で部分購読可能 |
| **デバッグツール** | Redux DevTools（強力） | React DevTools（基本的） | Flutter DevTools |
| **タイムトラベル** | ✅ 可能 | ❌ 不可 | BLoC Replay 機能に相当 |
| **ミドルウェア** | ✅ 充実 | ❌ なし | BLoC の transformers に相当 |
| **状態の永続化** | redux-persist | 手動実装 | hydrated_bloc に相当 |

### 1. **Redux の特徴**

#### メリット
```typescript
// ✅ 明確な状態の流れ
dispatch(action) → reducer → new state → UI update

// ✅ タイムトラベルデバッグ
// Redux DevTools で過去の状態に戻れる

// ✅ ミドルウェアで副作用を管理
const errorMiddleware = store => next => action => {
  if (action.type === 'api/error' && action.payload.status === 403) {
    store.dispatch(setForbiddenError(true))
  }
  return next(action)
}
```

**Flutter で言えば**: BLoC パターンに近い
- `Event` → `BLoC` → `State` → `UI` の一方向データフロー
- `bloc_test` でのタイムトラベルテスト
- `Transition` でのデバッグ

#### デメリット
```typescript
// ❌ ボイラープレートが多い
// slice 定義
const errorSlice = createSlice({...})
// reducer をストアに登録
export const rootReducer = combineReducers({...})
// グローバル dispatch の設定
setGlobalDispatch(dispatch)
```

**Flutter で言えば**: BLoC の冗長性
- Event クラス、State クラス、BLoC クラスの定義が必要
- `BlocProvider`、`BlocBuilder` の記述

### 2. **Context の特徴**

#### メリット
```typescript
// ✅ シンプル
const Context = createContext()
<Provider value={...}>{children}</Provider>
const value = useContext(Context)

// ✅ React の標準機能
// 追加ライブラリ不要

// ✅ 少ないコード量
// たった 1 ファイルで完結
```

**Flutter で言えば**: `Provider` パッケージ
- `ChangeNotifierProvider` でシンプルに状態管理
- `context.watch<T>()` で簡単にアクセス
- 公式推奨の軽量ソリューション

#### デメリット
```typescript
// ❌ パフォーマンスに注意が必要
// Context が更新されると、useContext を使っている
// すべてのコンポーネントが再レンダリング

const { hasForbiddenError, otherState } = useContext(MyContext)
// hasForbiddenError しか使わないのに、
// otherState が変わっても再レンダリングされる
```

**Flutter で言えば**: `InheritedWidget` の問題点
- `context.dependOnInheritedWidgetOfExactType` は全体を購読
- `Selector` で部分的な購読が必要

### 3. **今回のケースでの推奨**

**Context を推奨します**。理由：

#### ✅ Context が適している理由

1. **状態がシンプル**
```typescript
// たった 1 つの boolean フラグ
interface State {
  hasForbiddenError: boolean  // これだけ
}
```

**Flutter で言えば**: `ValueNotifier<bool>` で十分なケース
- 複雑な状態グラフが不要
- `setState(() => hasError = true)` レベルのシンプルさ

2. **更新頻度が低い**
```typescript
// 403 エラーは頻繁には発生しない
// アプリのライフサイクルで 0〜数回程度
```

**Flutter で言えば**: `StreamController<bool>.broadcast()` で十分
- 頻繁な更新でパフォーマンス問題が起きない

3. **グローバルな状態**
```typescript
// アプリ全体で 1 つの状態を共有
// 複数の独立した状態管理は不要
```

**Flutter で言えば**: `Provider<bool>` で全体を覆う
- 局所的な状態ではなくアプリレベルの状態

#### ❌ Redux が過剰な理由

```typescript
// ❌ オーバーエンジニアリング
// たった 1 つの boolean のために：
// - slice 定義
// - rootReducer への登録
// - グローバル dispatch の管理
// - DevTools の設定
```

**Flutter で言えば**: 
- `bool` 1 つのために BLoC を作るのは過剰
- `flutter_bloc` のパッケージ追加、Event/State クラス定義は不要

### 4. **Redux が適しているケース**

もしアプリが以下の要件を持つなら Redux を検討：

```typescript
// ✅ 複雑な状態管理
interface AppState {
  user: User
  teams: Team[]
  notifications: Notification[]
  filters: FilterState
  ui: UIState
  // ... 10+ のドメイン
}

// ✅ 複雑な状態遷移
// ユーザーアクション → 複数の state 更新
// 非同期処理の連鎖
// 楽観的更新とロールバック

// ✅ デバッグの必要性
// タイムトラベルデバッグ
// アクション履歴の記録
// 状態の再現
```

**Flutter で言えば**: 
- 大規模アプリで `flutter_bloc` が推奨されるケース
- E-commerce アプリ、SNS アプリなど
- 複雑なビジネスロジックと状態遷移

### 5. **その他の考慮事項**

#### チームの知識
```typescript
// 既存コードベースを確認
// web/src/store/ に Redux が既にある
// → チームは Redux に慣れている可能性

// しかし、たった 1 つの機能のために
// 新しい slice を追加するのは過剰
```

**Flutter で言えば**:
- プロジェクトが既に `flutter_bloc` を使っていても
- 小さな機能に `ValueNotifier` を使うのは妥当

#### 将来の拡張性
```typescript
// もし将来、以下が必要になったら Redux に移行を検討：
// - アクセス拒否の履歴記録
// - ユーザーへの通知システムとの統合
// - 複数種類のエラー状態管理
// - エラーからの自動リカバリー
```

## 最終推奨: カスタムイベント方式

実は、最もシンプルで React/Flutter に依存しない方法があります：

```typescript
// web/src/services/clients/web-api-client.ts
Axios.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error?.response?.status === 403) {
      if (typeof window !== 'undefined') {
        // カスタムイベントを発火（React 不要）
        window.dispatchEvent(new Event('app:accessDenied'))
      }
    }
    return Promise.reject(error)
  }
)

// web/src/layouts/root.layout.tsx
export default function RootLayout({ children }) {
  const [hasForbiddenError, setHasForbiddenError] = useState(false)

  useEffect(() => {
    const handler = () => setHasForbiddenError(true)
    window.addEventListener('app:accessDenied', handler)
    return () => window.removeEventListener('app:accessDenied', handler)
  }, [])

  return hasForbiddenError ? <AccessDenied /> : children
}
```

**Flutter で言えば**: 
```dart
// StreamController を使ったグローバルイベント
class AppEvents {
  static final accessDenied = StreamController<void>.broadcast();
}

// Dio Interceptor
onError: (error, handler) {
  if (error.response?.statusCode == 403) {
    AppEvents.accessDenied.add(null);
  }
  handler.next(error);
}

// UI
StreamBuilder(
  stream: AppEvents.accessDenied.stream,
  builder: (context, snapshot) {
    if (snapshot.hasData) return AccessDeniedWidget();
    return child;
  }
)
```

### メリット
- ✅ 最もシンプル（20 行程度）
- ✅ Context や Redux 不要
- ✅ グローバル変数不要
- ✅ ブラウザ標準の EventTarget API
- ✅ React の再レンダリング問題なし

### デメリット
- ❌ TypeScript の型安全性が弱い
- ❌ React DevTools で追跡できない
- ❌ SSR（サーバーサイドレンダリング）では動かない（`window` が存在しない）

## まとめ

| 方式 | コード量 | 学習コスト | パフォーマンス | 推奨度 |
|------|----------|------------|----------------|--------|
| **Context** | ⭐⭐⭐ 少 | ⭐⭐⭐ 低 | ⭐⭐ 中 | **🥇 最推奨** |
| **カスタムイベント** | ⭐⭐⭐⭐ 最少 | ⭐⭐⭐⭐ 最低 | ⭐⭐⭐ 高 | 🥈 次点 |
| **Redux** | ⭐ 多 | ⭐ 高 | ⭐⭐⭐ 高 | 大規模時のみ |

**Flutter エンジニアへのアドバイス**:
- シンプルな状態 → `Provider` や `ValueNotifier`（= React Context）
- 複雑な状態 → `BLoC` や `Riverpod`（= Redux）
- イベント通知 → `StreamController`（= カスタムイベント）

今回のケースは **Context 方式**（現在の実装）が最適です。

どの方式を採用したいですか？それとも他の実装を試してみたいですか？

