import type { PayloadAction } from '@reduxjs/toolkit';
import { createSlice } from '@reduxjs/toolkit';

import { PitchType } from '@/models/pitch-type';

interface MasterDataState {
  pitchTypes: PitchType[];
  deploymentCheckedAt: Date | null;
  maintenanceCheckedAt: Date | null;
}

const initialState: MasterDataState = {
  pitchTypes: [],
  deploymentCheckedAt: null,
  maintenanceCheckedAt: null,
};

const slice = createSlice({
  name: 'master',
  initialState,
  reducers: {
    setPitchTypes(
      state: MasterDataState,
      action: PayloadAction<PitchType[] | null>,
    ): void {
      state.pitchTypes = action.payload ?? [];
    },
    setDeploymentCheckedDate(
      state: MasterDataState,
      action: PayloadAction<Date>,
    ): void {
      const data = action.payload;
      state.deploymentCheckedAt = data;
    },
    setMaintenanceCheckedDate(
      state: MasterDataState,
      action: PayloadAction<Date>,
    ): void {
      const data = action.payload;
      state.maintenanceCheckedAt = data;
    },
  },
});

export const { reducer, actions } = slice;

content.text:
既存の Redux の使用状況を確認しました。**結論から言うと、Redux と Context の併用は問題ありません**。むしろ、それぞれの強みを活かした良い設計パターンです。

## Redux と Context の併用について

### ✅ 併用は一般的で推奨されるパターンです

React 公式ドキュメントでも、Redux と Context の併用は認められており、実際多くのプロダクションアプリで使われています。

**Flutter で言えば**:
```dart
// BLoC と Provider を併用するのと同じ
class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MultiBlocProvider(
      providers: [
        BlocProvider(create: (_) => UserBloc()),      // 複雑な状態
        BlocProvider(create: (_) => MasterDataBloc()), // 複雑な状態
      ],
      child: Provider<ErrorNotifier>(               // シンプルな状態
        create: (_) => ErrorNotifier(),
        child: MaterialApp(...),
      ),
    );
  }
}
```

### 📊 このアプリでの使い分け

現在のアプリでは、以下のように使い分けられています：

#### Redux で管理（複雑な状態）
```typescript
// user.slice.ts - 複雑なユーザー状態
interface UserDataState {
  me: User | null                    // ユーザー情報
  accessibleTeams: Team[]            // アクセス可能なチーム一覧
  currentTeam: Team | null           // 現在選択中のチーム
  error: ServiceError | null         // エラー
  loginStatus: 'unknown' | 'yes' | 'no' | 'error' | 'initial'
  unit: SupportedUnit                // 単位設定
}

// master.slice.ts - マスターデータ
interface MasterDataState {
  pitchTypes: PitchType[]           // 球種マスター
  deploymentCheckedAt: Date | null   // デプロイ確認日時
  maintenanceCheckedAt: Date | null  // メンテナンス確認日時
}
```

**Redux が適切な理由**:
- ✅ 複雑な状態（6 つのプロパティ、ネストしたオブジェクト）
- ✅ 複数の画面で共有される
- ✅ 状態の更新ロジックが複雑（`setTeams` の条件分岐など）
- ✅ デバッグが重要（ユーザー認証周り）

#### Context で管理（シンプルな状態）
```typescript
// access-denied.context.tsx - 403 エラーフラグ
interface AccessDeniedContextType {
  hasForbiddenError: boolean  // たった 1 つの boolean
}
```

**Context が適切な理由**:
- ✅ 非常にシンプルな状態（1 つの boolean）
- ✅ 更新頻度が低い（403 エラーは稀）
- ✅ 一時的な UI 状態（ページリロードで消える）
- ✅ Redux の複雑さが不要

### 🎯 使い分けの原則

**Flutter エンジニア向けに言い換えると**:

```dart
// ■ Redux（BLoC）を使うべき状態
// - ビジネスロジックの状態
// - 永続化が必要な状態
// - 複数画面で共有される状態
// - 複雑な状態遷移がある

class UserBloc extends Bloc<UserEvent, UserState> {
  // ユーザー情報、認証状態など
}

// ■ Context（Provider / ChangeNotifier）を使うべき状態
// - UI の一時的な状態
// - シンプルな boolean フラグ
// - 特定の機能に限定された状態

class ErrorNotifier extends ChangeNotifier {
  bool _hasError = false;
  bool get hasError => _hasError;
  void setError(bool value) {
    _hasError = value;
    notifyListeners();
  }
}
```

### 📚 実際の使用例

このアプリでの実際の使われ方：

```typescript
// ■ Redux を使っている場所
const currentUser = useSelector((state) => state.user.me)
const teams = useSelector((state) => state.user.accessibleTeams)
const currentTeam = useSelector((state) => state.user.currentTeam)

// ユーザー情報は複数のページで使われる重要な状態
// → Redux で一元管理が適切

// ■ Context を使っている場所
const { hasForbiddenError } = useAccessDenied()

// 403 エラーはアプリ全体の一時的な UI 状態
// → Context でシンプルに管理が適切
```

### ⚠️ 注意すべきポイント

#### 1. **状態の重複を避ける**

```typescript
// ❌ 悪い例：同じ状態を Redux と Context の両方で管理
// Redux
interface UserState {
  hasForbiddenError: boolean  // ❌
}

// Context
interface AccessDeniedContext {
  hasForbiddenError: boolean  // ❌ 重複！
}

// ✅ 良い例：役割を明確に分ける
// Redux: ビジネスロジックの状態
interface UserState {
  me: User | null
  loginStatus: string
}

// Context: UI の一時的な状態
interface AccessDeniedContext {
  hasForbiddenError: boolean
}
```

**Flutter で言えば**:
```dart
// ❌ 同じデータを BLoC と Provider の両方で持つのは NG
class UserBloc {
  bool hasError; // ❌
}
class ErrorProvider {
  bool hasError; // ❌ 重複
}

// ✅ 役割を分ける
class UserBloc {
  User? user;
  String loginStatus;
}
class ErrorNotifier {
  bool hasError; // UI 状態のみ
}
```

#### 2. **依存関係を明確にする**

```typescript
// ✅ Context は Redux に依存しない（独立）
// Context 単体でも動作する

// ✅ Redux は Context を知らない（疎結合）
// Redux の slice は Context の存在を意識しない
```

### 🏗️ アーキテクチャ上の利点

```
┌─────────────────────────────────────┐
│          Application Layer           │
├─────────────────────────────────────┤
│                                       │
│  ┌──────────────┐  ┌──────────────┐ │
│  │   Redux      │  │   Context    │ │
│  │              │  │              │ │
│  │ ・User       │  │ ・403 Error  │ │
│  │ ・Teams      │  │              │ │
│  │ ・Master     │  │              │ │
│  │              │  │              │ │
│  │ (複雑な状態) │  │(シンプルな状態)│ │
│  └──────────────┘  └──────────────┘ │
│                                       │
└─────────────────────────────────────┘
```

**Flutter で言えば**:
```
┌─────────────────────────────────────┐
│          MaterialApp                 │
├─────────────────────────────────────┤
│                                       │
│  ┌──────────────┐  ┌──────────────┐ │
│  │ BlocProvider │  │   Provider   │ │
│  │              │  │              │ │
│  │ ・UserBloc   │  │・ErrorNotifier│ │
│  │ ・TeamBloc   │  │              │ │
│  │              │  │              │ │
│  │ (複雑な状態) │  │(シンプルな状態)│ │
│  └──────────────┘  └──────────────┘ │
│                                       │
└─────────────────────────────────────┘
```

### 📖 業界のベストプラクティス

実際の大規模 React アプリケーションでは、以下のように併用されています：

1. **Redux**: ビジネスロジック、サーバーデータ、認証状態
2. **Context**: テーマ、言語設定、一時的な UI 状態
3. **Local State**: コンポーネント内の UI 状態

**Flutter で言えば**:
1. **BLoC/Riverpod**: ビジネスロジック、API データ、認証
2. **Provider**: テーマ、ロケール、グローバル UI 状態
3. **setState**: ウィジェット内の UI 状態

### ✅ まとめ

**Redux と Context の併用は全く問題ありません**。むしろ推奨されるパターンです。

重要なのは、**それぞれの強みを活かして適材適所で使い分ける**ことです：

| 状態の種類 | 使うべき技術 | このアプリでの例 |
|------------|--------------|------------------|
| 複雑なビジネスロジック | Redux | User, Teams, Master |
| シンプルな UI 状態 | Context | 403 Error フラグ |
| コンポーネント内 UI | useState | モーダルの開閉状態 |

現在の実装は、この原則に沿った良い設計になっています。

May the Force be with you.

