   131→    icon: <AdminPanelSettingsOutlined />,
   132→    isSelected: router.pathname == PAGE_INFO.ADMIN.href(currentTeam.id),
   133→    link: PAGE_INFO.ADMIN.href(currentTeam.id),
   134→  };
   135→
   136→  const superAdminItems = [
   137→    {
   138→      name: translate(
   139→        PAGE_INFO.SUPER_ADMIN_RESOURCES.name as keyof typeof translate,
   140→      ),
   141→      icon: <AdminPanelSettings />,
   142→      isSelected: router.pathname == PAGE_INFO.SUPER_ADMIN_RESOURCES.href(),
   143→      link: PAGE_INFO.SUPER_ADMIN_RESOURCES.href(),
   144→    },
   145→    {
   146→      name: translate(
   147→        PAGE_INFO.SUPER_ADMIN_TEAMS.name as keyof typeof translate,
   148→      ),
   149→      icon: <AdminPanelSettings />,
   150→      isSelected: router.pathname == PAGE_INFO.SUPER_ADMIN_TEAMS.href(),
   151→      link: PAGE_INFO.SUPER_ADMIN_TEAMS.href(),
   152→    },
   153→    {
   154→      name: translate(
   155→        PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS.name as keyof typeof translate,
   156→      ),
   157→      icon: <AdminPanelSettings />,
   158→      isSelected: router.pathname == PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS.href(),
   159→      link: PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS.href(),
   160→    },
   161→    {
   162→      name: translate(
   163→        PAGE_INFO.SUPER_ADMIN_AI_COACH.name as keyof typeof translate,
   164→      ),
   165→      icon: <AdminPanelSettings />,
   166→      isSelected: router.pathname == PAGE_INFO.SUPER_ADMIN_AI_COACH.href(),
   167→      link: PAGE_INFO.SUPER_ADMIN_AI_COACH.href(),
   168→    },
   169→    {
   170→      name: translate(
   171→        PAGE_INFO.SUPER_ADMIN_ITEMS.name as keyof typeof translate,
   172→      ),
   173→      icon: <Inventory2Outlined />,
   174→      isSelected: router.pathname == PAGE_INFO.SUPER_ADMIN_ITEMS.href(),
   175→      link: PAGE_INFO.SUPER_ADMIN_ITEMS.href(),
   176→    },
   177→  ];
   178→
   179→  const menuItems: MenuItemDataType[] = [
   180→    {
   181→      name: translate(PAGE_INFO.SESSIONS.name as keyof typeof translate),
   182→      icon: <FormatListBulleted />,
   183→      isSelected: router.pathname == PAGE_INFO.SESSIONS.href(currentTeam.id),
   184→      link: PAGE_INFO.SESSIONS.href(currentTeam.id),
   185→    },
   186→    {
   187→      name: translate(PAGE_INFO.PLAYERS.name as keyof typeof translate),
   188→      icon: <Groups3Outlined />,
   189→      isSelected: router.pathname == PAGE_INFO.PLAYERS.href(currentTeam.id),
   190→      link: PAGE_INFO.PLAYERS.href(currentTeam.id),
   191→    },
   192→    ...(User.isAccessible(
   193→      currentUser,
   194→      currentTeam.id,
   195→      'management',
   196→      'read',
   197→      true,
   198→    )
   199→      ? [adminItem]
   200→      : []),
   201→    {
   202→      name: '_divider_0',
   203→      icon: <></>,
   204→      isDivider: true,
   205→    },
   206→    {
   207→      name: translate(PAGE_INFO.NOTIFICATIONS.name as keyof typeof translate),
   208→      icon: <NotificationsOutlined />,
   209→      isSelected: router.pathname == PAGE_INFO.NOTIFICATIONS.href(),
   210→      link: PAGE_INFO.NOTIFICATIONS.href(),
   211→    },
   212→    ...(User.isAccessible(currentUser, 'all', 'admin', 'read', false)
   213→      ? [
   214→          {
   215→            name: '_divider_2',
   216→            icon: <></>,
   217→            isDivider: true,
   218→          },
   219→          ...superAdminItems,
   220→        ]
   221→      : []),
   222→  ];
   223→
   224→  const closeDrawerOnSmallScreen = () => {
   225→    if (isSmallScreen) {
   226→      setOpen(false);
   227→    }
   228→  };
   229→
   230→  // プランステータスの判定
   231→  const getPlanStatus = (): { status: PlanStatus | null } => {
   232→    if (currentTeam.teamType === TeamType.MULTIPLE) {
   233→      return { status: null };
   234→    }
   235→
   236→    // 期限内のAppleサブスクリプションがある場合は表示しない
   237→    if (currentTeam.teamPlan?.isInAppleSubscription) {
   238→      return { status: null };
   239→    }
   240→
   241→    // 支払い失敗の場合
   242→    if (
   243→      currentTeam.billingFailureReason !== null &&
   244→      currentTeam.billingFailureReason !== ''
   245→    ) {
   246→      return { status: 'billing_failure' };
   247→    }
   248→
   249→    // teamPlan が無料プランの場合
   250→    if (!currentTeam.teamPlan?.plan.isPaid) {
   251→      return { status: 'upgrade_prompt' };
   252→    }
   253→
   254→    // プランが利用不可の場合（期限切れや利用制限に達している場合）
   255→    if (!currentTeam.teamPlanAvailability.isAvailable) {
   256→      const reason = currentTeam.teamPlanAvailability.unavailableReason;
   257→      if (reason === 'team_plan_expired' || reason === 'no_team_plan_found') {
   258→        return { status: 'upgrade_prompt' };
   259→      }
   260→    }
   261→
   262→    // 既存のplanがisTopTierPlanの場合は表示しない
   263→    if (isTopTierPlan(currentTeam.teamPlan?.plan.id)) {
   264→      return { status: null };
   265→    }
   266→
   267→    // 利用制限に達している場合
   268→    if (currentTeam.ballRate >= 1) {
   269→      return { status: 'limit_reached' };
   270→    }
   271→
   272→    // 利用制限が近づいている場合
   273→    const isUsageLimitApproaching = currentTeam.ballRate >= 0.9;
   274→    if (isUsageLimitApproaching) {
   275→      return { status: 'pre_warning' };
   276→    }
   277→
   278→    // その他の場合は常にUpgrade promptを表示
   279→    return { status: 'upgrade_prompt' };
   280→  };
   281→
   282→  const planStatus = getPlanStatus();
   283→
   284→  const handleUpgrade = () => {
   285→    // 期限内のAppleサブスクリプションがある場合は何もしない
   286→    if (currentTeam.teamPlan?.isInAppleSubscription) {
   287→      return;
   288→    }
   289→    // 期限内のStripeサブスクリプションがある場合は請求ポータルを開く
   290→    if (currentTeam.teamPlan?.isInStripeSubscription) {
   291→      handleBillingPortal(planStatus.status);
   292→      return;
   293→    }
   294→    // その他の場合はプラン選択ページに遷移
   295→    router.push('/account/plans');
   296→  };
   297→
   298→  const handleBillingPortal = async (status: PlanStatus | null) => {
   299→    try {
   300→      let type:
   301→        | 'subscription_update'
   302→        | 'subscription_cancel'
   303→        | 'payment_method_update'
   304→        | undefined;
   305→      if (status === 'billing_failure') {
   306→        type = 'payment_method_update';
   307→      } else if (
   308→        status === 'upgrade_prompt' ||
   309→        status === 'pre_warning' ||
   310→        status === 'limit_reached'
   311→      ) {
   312→        type = 'subscription_update';
   313→      }
   314→
   315→      const result = await services.default.payment.createBillingPortalSession({
   316→        teamId: currentTeam.id,
   317→        type,
   318→      });
   319→      if (result.error) {
   320→        throw result.error;
   321→      }
   322→      if (result.data?.url) {
   323→        window.open(result.data.url, '_blank', 'noopener,noreferrer');
   324→      }
   325→    } catch (error) {
   326→      enqueueSnackbar({
   327→        variant: 'error',
   328→        message: translate('payment_error_occurred'),
   329→      });
   330→    }
   331→  };
   332→
   333→  return (
   334→    <>
   335→      <Box sx={{ display: { xs: 'block', md: 'none' } }}>
   336→        <Slide appear={false} direction="down" in={!scrollTrigger}>
   337→          <AppBar variant="outlined" color="inherit" elevation={0}>
   338→            <Toolbar sx={{ display: 'flex', justifyContent: 'space-between' }}>
   339→              <Box sx={{ display: 'flex', flex: 1 }}>
   340→                <IconButton
   341→                  size="large"
   342→                  edge="start"
   343→                  color="inherit"
   344→                  aria-label="menu"
   345→                  sx={{ mr: 2 }}
   346→                  onClick={flipOpen}
   347→                >
   348→                  <MenuIcon />
   349→                </IconButton>
   350→              </Box>
   351→              <Box sx={{ display: 'flex', flex: 1, justifyContent: 'center' }}>
   352→                <Image
   353→                  src={AppConstants.LOGO_URL}
   354→                  alt=""
   355→                  priority={true}
   356→                  height="40"
   357→                  width="150"
   358→                />
   359→              </Box>
   360→              <Box sx={{ display: 'flex', flex: 1 }} />
   361→            </Toolbar>
   362→          </AppBar>
   363→        </Slide>
   364→        <Toolbar />
   365→      </Box>
   366→      <Box sx={{ display: 'flex' }}>
   367→        <Drawer
   368→          open={open}
   369→          onClose={flipOpen}
   370→          variant={isSmallScreen ? 'temporary' : 'permanent'}
   371→          slotProps={{
   372→            root: {
   373→              keepMounted: true, // Better open performance on mobile.
   374→            },
   375→          }}
   376→        >
   377→          <List sx={{ flex: 1 }}>
   378→            <ListItem disablePadding>
   379→              <ListItemButton
   380→                onClick={flipOpen}
   381→                sx={{
   382→                  justifyContent: 'space-between',
   383→                }}
   384→              >
   385→                <Image
   386→                  src={AppConstants.LOGO_URL}
   387→                  alt=""
   388→                  priority={true}
   389→                  height="40"
   390→                  width="150"
   391→                  style={{ display: open ? 'block' : 'none' }}
   392→                />
   393→                <ListItemIcon
   394→                  sx={{
   395→                    minWidth: 0,
   396→                    mr: open ? 1 : 'auto',
   397→                    justifyContent: 'center',
   398→                  }}
   399→                >
   400→                  {open ? (
   401→                    <KeyboardDoubleArrowLeft />
   402→                  ) : (
   403→                    <KeyboardDoubleArrowRight />
   404→                  )}
   405→                </ListItemIcon>
   406→              </ListItemButton>
   407→            </ListItem>
   408→            <Divider sx={{ mt: 2, mb: 6 }} />
   409→            <ListItem sx={{ opacity: open ? 1 : 0, mb: 2, py: 0 }}>
   410→              <Typography>{translate('navigation')}</Typography>
   411→            </ListItem>
   412→            {menuItems.map((x) => {
   413→              return (
   414→                <React.Fragment key={x.name}>
   415→                  {x.link ? (
   416→                    <ListItem disablePadding>
   417→                      <Link
   418→                        href={x.link}
   419→                        passHref
   420→                        style={{ width: '100%', textDecoration: 'none' }}
   421→                        onClick={closeDrawerOnSmallScreen}
   422→                      >
   423→                        <ListItemButton
   424→                          selected={!!x.isSelected}
   425→                          sx={{
   426→                            justifyContent: 'center',
   427→                          }}
   428→                        >
   429→                          <ListItemIcon
   430→                            sx={{
   431→                              minWidth: 0,
   432→                              mr: open ? 3 : 'auto',
   433→                              justifyContent: 'center',
   434→                            }}
   435→                          >
   436→                            {x.icon}
   437→                          </ListItemIcon>
   438→                          <ListItemText
   439→                            primary={x.name}
   440→                            sx={{
   441→                              opacity: open ? 1 : 0,
   442→                            }}
   443→                          />
   444→                        </ListItemButton>
   445→                      </Link>
   446→                    </ListItem>
   447→                  ) : x.isDivider ? (
   448→                    <Divider sx={{ my: 1 }} />
   449→                  ) : (
   450→                    <></>
   451→                  )}
   452→                </React.Fragment>
   453→              );
   454→            })}
   455→          </List>
   456→
   457→          {/* Plan Status Card */}
   458→          {planStatus.status !== null && (
   459→            <PlanStatusCard
   460→              status={planStatus.status}
   461→              open={open}
   462→              onUpgrade={handleUpgrade}
   463→              billingFailureReason={currentTeam.billingFailureReason}
   464→            />
   465→          )}
   466→
   467→          {/* TODO: remove this */}
   468→          {!EnvManager.isPrd && (
   469→            // NOTE: Nest Box components to avoid the effects of flex and
   470→            // prevent the vertical size from shrinking
   471→            <Box>
   472→              <Box
   473→                className={'develop'}
   474→                sx={{
   475→                  padding: 0.5,
   476→                  background: 'lightgray',
   477→                  height: '100%',
   478→                  overflowX: 'hidden',
   479→                  textOverflow: 'ellipsis',
   480→                }}
   481→              >
   482→                build: {EnvManager.config.APP_UPDATED_AT}
   483→                <br />
   484→                commit: {EnvManager.config.GIT_COMMIT_HASH}
   485→                <br />
   486→              </Box>
   487→            </Box>
   488→          )}
   489→
   490→          <Box>
   491→            <Divider></Divider>
   492→            <Link
   493→              href={PAGE_INFO.ACCOUNT.href()}
   494→              passHref
   495→              style={{ width: '100%', textDecoration: 'none' }}
   496→              onClick={closeDrawerOnSmallScreen}
   497→            >
   498→              <ListItemButton
   499→                selected={
   500→                  router.pathname == PAGE_INFO.ACCOUNT.href() ||
   501→                  router.pathname == PAGE_INFO.ACCOUNT_EDIT.href()
   502→                }
   503→                sx={{
   504→                  justifyContent: 'center',
   505→                }}
   506→              >
   507→                <ListItemIcon
   508→                  sx={{
   509→                    minWidth: 0,
   510→                    mr: open ? 3 : 'auto',
   511→                    justifyContent: 'center',
   512→                  }}
   513→                >
   514→                  <ImageOrAvatar
   515→                    url={currentUser.profile?.presignedImageUrl}
   516→                    width={40}
   517→                    height={40}
   518→                  />
   519→                </ListItemIcon>
   520→                <ListItemText
   521→                  primary={currentUser?.profile?.username ?? '-'}
   522→                  sx={{
   523→                    opacity: open ? 1 : 0,
   524→                  }}
   525→                  slotProps={{
   526→                    primary: {
   527→                      sx: {
   528→                        overflowX: 'hidden',
   529→                        textOverflow: 'ellipsis',
   530→                      },
   531→                    },
   532→                  }}
   533→                />
   534→              </ListItemButton>
   535→            </Link>
   536→          </Box>
   537→        </Drawer>
   538→        <Box
   539→          component="main"
   540→          sx={{
   541→            flexGrow: 1,
   542→            py: 2,
   543→            px: 2,
   544→            overflowX: 'auto',
   545→            minHeight: '100vh',
   546→            background: '#F9F9F9',
   547→          }}
   548→        >
   549→          {children}
   550→        </Box>
   551→      </Box>
   552→    </>
   553→  );
   554→}
   555→
   556→export default function ConsoleLayout({ children }: { children: ReactNode }) {
   557→  const { services, router } = useServicesHook();
   558→  const [_, setIsSubmitting] = useState<boolean>(false);
   559→  const currentUser = useSelector((state) => state.user.me);
   560→  const currentTeam = useSelector((state) => state.user.currentTeam);
   561→  const userError = useSelector((state) => state.user.error);
   562→  const loginStatus = useSelector((state) => state.user.loginStatus);
   563→
   564→  const logout = () => {
   565→    wrapForLoading(setIsSubmitting, async () => {
   566→      await services.default.auth.signOut();
   567→      location.href = PAGE_INFO.SIGN_IN.href();
   568→    });
   569→  };
   570→
   571→  useEffect(() => {
   572→    if (loginStatus === 'initial') {
   573→      return;
   574→    }
   575→
   576→    if (loginStatus != 'yes') {
   577→      logger.debug('SD: no user - redirect to signin');
   578→      const callbackUrl = createSafeCallbackUrl();
   579→      router.replace(`${PAGE_INFO.SIGN_IN.href()}?callbackUrl=${callbackUrl}`);
   580→    }
   581→  }, [loginStatus]);
   582→
   583→  if (loginStatus == 'error' && userError) {
   584→    return (
   585→      <>
   586→        <CriticalError error={userError} />
   587→      </>
   588→    );
   589→  }
   590→
   591→  return currentUser && currentTeam ? (
   592→    <LayoutInner currentUser={currentUser} currentTeam={currentTeam}>
   593→      {children}
   594→    </LayoutInner>
   595→  ) : currentUser ? (
   596→    <Box
   597→      sx={{
   598→        p: 2,
   599→      }}
   600→    >
   601→      <Typography>{translate('no_active_teams_found')}</Typography>
   602→      <Button color="error" sx={{ mt: 2 }} variant="contained" onClick={logout}>
   603→        {translate('sign_out')}
   604→      </Button>
   605→    </Box>
   606→  ) : (
   607→    <>
   608→      {
   609→        // nothing to do (waiting initialization)
   610→      }
   611→    </>
   612→  );
   613→}
