import _ from 'lodash';
import Head from 'next/head';
import { ReactNode, useEffect } from 'react';

import AccessDenied from '@/components/common/access-denied';
import { EnvManager } from '@/constants/env.constants';
import { useAccessDenied } from '@/contexts/access-denied.context';
import useServicesHook from '@/hooks';

/**
 * Get page title based on environment
 */
function getPageTitle(): string {
  const env = EnvManager.config.APP_ENV;

  switch (env) {
    case 'develop':
      return 'SmartScout [DEV]';
    case 'staging':
      return 'SmartScout [STG]';
    case 'production':
    default:
      return 'SmartScout';
  }
}

export default function RootLayout({ children }: { children: ReactNode }) {
  const { router } = useServicesHook();
  const { hasForbiddenError } = useAccessDenied();

  useEffect(() => {
    if (
      EnvManager.config.ENABLE_PRODUCTION_REDIRECT &&
      _.trim(router.asPath, '/') != 'redirect-to-production'
    ) {
      location.href = '/redirect-to-production';
    }
  }, []);

  return (
    <>
      <Head>
        <title>{getPageTitle()}</title>
        {
          // metaタグとか
        }
      </Head>
      {hasForbiddenError ? <AccessDenied /> : children}
    </>
  );
}

