      const setter = getGlobalAccessDeniedSetter();
      if (setter) {
        setter(false);
      }
    }
    return response;
  },
  async (error) => {
    // 403 Forbidden エラーの場合、グローバル状態を更新
    if (error?.response?.status === 403) {
      // クライアントサイドでのみ実行（SSRでは実行しない）
      if (typeof window !== 'undefined') {
        const { getGlobalAccessDeniedSetter } = await import(
          '@/contexts/access-denied.context'
        );
        const setter = getGlobalAccessDeniedSetter();
        if (setter) {
          setter(true);
        }
      }
    }
    return Promise.reject(error);
  },
);
```

**Why Important**: This is the core of the global 403 handling - intercepts all API responses and sets error state on 403, clears it on success.

