  async (response) => {
    // 成功レスポンスの場合、403 エラー状態をクリア
    if (typeof window !== 'undefined') {
      const { getGlobalAccessDeniedSetter } = await import('@/contexts/access-denied.context');
      const setter = getGlobalAccessDeniedSetter();
      if (setter) {
        setter(false);
      }
    }
    return response;
  },
