   362→          onSuccess={() => {
   363→            setIsOkModalOpen(true);
   364→            setOkModalText(translate('the_user_has_been_re_added'));
   365→          }}
   366→        />
   367→
   368→        {editingTeam && (
   369→          <EditTeamModal
   370→            teamId={currentTeam.id}
   371→            defaultData={{
   372→              name: currentTeam.name!,
   373→              previewUrl: currentTeam.presignedImageUrl,
   374→            }}
   375→            isOpen={isEditTeamModalOpen}
   376→            setIsOpen={setIsEditTeamModalOpen}
   377→            onSuccess={(team: Team) => {
   378→              reloadTeam(team);
   379→            }}
   380→            onCancel={() => {
   381→              setEditingTeam(null);
   382→            }}
   383→          />
   384→        )}
   385→
   386→        <OkModal
   387→          isOpen={isOkModalOpen}
   388→          setIsOpen={setIsOkModalOpen}
   389→          title={okModalText}
   390→        />
   391→
   392→        {/* [HEADER] */}
   393→        <Stack direction="row" alignItems="center" sx={{ py: 1 }}>
   394→          <Image
   395→            src={
   396→              currentTeam?.presignedImageUrl ??
   397→              AppConstants.NO_IMAGE_2ND_BASE_URL
   398→            }
   399→            alt=""
   400→            width="120"
   401→            height="120"
   402→          />
   403→          <Stack
   404→            direction="row"
   405→            sx={{ alignItems: 'center', flex: 1, px: 3, py: 1 }}
   406→          >
   407→            {/* multiple team:チーム名, single team:ユーザー管理 */}
   408→            <Typography variant="h1">
   409→              {currentTeam.teamType === TeamType.SINGLE
   410→                ? translate('page_admin')
   411→                : currentTeam?.name}
   412→            </Typography>
   413→            {hasManagementWriteAccess ? (
   414→              <Button
   415→                sx={{ color: '#707070', textDecoration: 'underline' }}
   416→                color="neutral"
   417→                onClick={() => {
   418→                  setEditingTeam(currentTeam);
   419→                  setIsEditTeamModalOpen(true);
   420→                }}
   421→              >
   422→                {translate('edit')}
   423→              </Button>
   424→            ) : (
   425→              ''
   426→            )}
   427→            <ValidationError
   428→              error={error}
   429→              pos={['name']}
   430→              sx={{ ml: 1, mt: 1 }}
   431→            />
   432→          </Stack>
   433→        </Stack>
   434→        <Divider sx={{ mt: 2 }} />
   435→
   436→        {/* [MAIN CONTENT] */}
   437→        <Card sx={{ backgroundColor: 'white', p: 2 }}>
   438→          <Stack
   439→            direction={{ xs: 'column', md: 'row-reverse' }}
   440→            spacing={2}
   441→            justifyContent="space-between"
   442→          >
   443→            <DefaultSearchField
   444→              value={conditions.keyword}
   445→              onSearch={() => {
   446→                const newData = {
   447→                  ...conditions,
   448→                  currentPage: 0,
   449→                };
   450→                updateQueryParameters(newData);
   451→              }}
   452→              onChange={(e) => {
   453→                setConditions({
   454→                  ...conditions,
   455→                  keyword: e.target.value,
   456→                });
   457→              }}
   458→            />
   459→            <Grid container direction="row" spacing={1} sx={{ flex: 1 }}>
   460→              <Grid size="auto">
   461→                <FormControl size="small" variant="standard">
   462→                  <Select
   463→                    value={conditions.sort}
   464→                    onChange={(e) => {
   465→                      const newData = {
   466→                        ...conditions,
   467→                        sort: e.target.value as UserSortType,
   468→                        currentPage: 0,
   469→                      };
   470→                      setConditions(newData);
   471→                      updateQueryParameters(newData);
   472→                    }}
   473→                  >
   474→                    {sortOptions.map((x) => {
