   566→                                } else {
   567→                                  closeMenu();
   568→                                }
   569→                              }}
   570→                            >
   571→                              <MoreHoriz />
   572→                            </Button>
   573→
   574→                            <Menu
   575→                              onClose={closeMenu}
   576→                              anchorEl={anchorEl}
   577→                              open={selectedProfileId === user.id}
   578→                            >
   579→                              {_.first(user.givenUserRoles[teamId])
   580→                                ?.deleteFlag && currentUser.id != user.id ? (
   581→                                <>
   582→                                  <MenuItem
   583→                                    onClick={() => {
   584→                                      // banned and not the same user as currentUser
   585→                                      setUserToReactivate(user);
   586→                                      closeMenu();
   587→                                    }}
   588→                                  >
   589→                                    {translate('reactivate')}
   590→                                  </MenuItem>
   591→                                </>
