   621→                                </>
   622→                              ) : (
   623→                                ''
   624→                              )}
   625→                            </Menu>
   626→                          </>
   627→                        ) : (
   628→                          ''
   629→                        )}
   630→                      </TableCell>
   631→                    </TableRow>
   632→                  ))}
   633→                </TableBody>
   634→              </Table>
   635→            </TableContainer>
   636→          )}
   637→          <CommonPagination
   638→            user={currentUser}
   639→            numberOfTotalItems={numberOfTotalItems}
   640→            commonPaginationData={{
   641→              currentPage: conditions.currentPage,
