   645→              updateQueryParameters({
   646→                ...conditions,
   647→                ...data,
   648→              });
   649→            }}
   650→          />
   651→        </Card>
   652→      </Stack>
   653→      {hasManagementWriteAccess && (
   654→        <FloatingButton
   655→          icon={<PersonAddAlt />}
   656→          title={translate('invite_member')}
   657→          onClick={() => {
   658→            setAddProfileModalParam({
   659→              ...inviteProfileModalParamDefault(currentTeam),
   660→              isEditing: true,
   661→            });
   662→          }}
   663→        />
   664→      )}
   665→    </Container>
   666→  );
   667→}
   668→
   669→export default function Page() {
   670→  const { router } = useServicesHook();
   671→  const currentUser = useSelector((state) => state.user.me);
   672→  const teams = useSelector((state) => state.user.accessibleTeams);
   673→  const [team, setTeam] = useState<Team>();
   674→  const teamId = router.query.team_id?.toString();
   675→
   676→  useEffect(() => {
   677→    if (!teamId) {
   678→      return;
   679→    }
