import { MoreHoriz, PersonAddAlt } from '@mui/icons-material';
import {
  Box,
  Button,
  Card,
  CircularProgress,
  Container,
  Divider,
  FormControl,
  Grid2 as Grid,
  Menu,
  MenuItem,
  Paper,
  Select,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Typography,
} from '@mui/material';
import _ from 'lodash';
import Image from 'next/image';
import React, { ReactElement, useEffect, useMemo, useState } from 'react';

import AccessDenied from '@/components/common/access-denied';
import CriticalError from '@/components/common/critical-error';
import { FloatingButton } from '@/components/common/floating-button';
import { ImageOrAvatar } from '@/components/common/image-or-avatar';
import DefaultSearchField from '@/components/common/input/default-search-field';
import ValidationError from '@/components/common/validation-error';
import { OkModal } from '@/components/modal/ok-modal';
import { DeactivateProfileModal } from '@/components/modal/profile/deactivate-profile-modal';
import { EditProfileModal } from '@/components/modal/profile/edit-profile-modal';
import {
  InviteProfileModal,
  InviteProfileModalParam,
  inviteProfileModalParamDefault,
} from '@/components/modal/profile/invite-profile-modal';
import { ReactivateUserModal } from '@/components/modal/profile/reactivate-user-modal';
import { EditTeamModal } from '@/components/modal/team/edit-team-modal';
import {
  CommonPagination,
  CommonPaginationData,
} from '@/components/pagination/common-pagination';
import AppConstants from '@/constants/app.constants';
import { PAGE_INFO } from '@/constants/page.constants';
import useServicesHook from '@/hooks';
import ConsoleLayout from '@/layouts/console.layout';
import { Team, TeamType } from '@/models/team';
import { AppRoles } from '@/models/types';
import { User } from '@/models/user';
import { ServiceError } from '@/services/errors/service-error';
import {
  UserSortType,
  userSortTypes,
} from '@/services/interfaces/users-api.interface';
import { useSelector } from '@/store';
import { actions as userDataActions } from '@/store/slices/user.slice';
import { translate } from '@/utils/i18n';
import { PathUtil } from '@/utils/path.util';
import { userRoleToDispName } from '@/utils/user-role-util';

type AdminQueryCondition = {
  keyword: string;
  sort: UserSortType;
  searchTrigger: Date;
};

const defaultCondition: AdminQueryCondition & CommonPaginationData = {
  keyword: '',
  sort: 'name',
  currentPage: 0,
  rowsPerPage: 10,

  searchTrigger: new Date(),
};

const buildQueryParam = (data: AdminQueryCondition & CommonPaginationData) => {
  return {
    keyword: data.keyword.toString(),
    sort: data.sort.toString(),
    page: data.currentPage.toString(),
    pageSize: data.rowsPerPage.toString(),
  };
};

const parseQueryParam = (data: any) => {
  return _.chain({
    keyword: PathUtil.getStringFromQuery(data.keyword),
    sort: PathUtil.getEnumFromQuery(userSortTypes, data.sort),
    currentPage: PathUtil.getIntFromQuery(data.page),
    rowsPerPage: PathUtil.getIntFromQuery(data.pageSize),
  })
    .omitBy((v, k) => {
      return _.isNil(v);
    })
    .defaultsDeep(defaultCondition)
    .value();
};

function PageInner({
  currentUser,
  currentTeam,
}: {
  currentUser: User;
  currentTeam: Team;
}) {
  const { services, router, reloader, dispatch } = useServicesHook();
  const teams = useSelector((state) => state.user.accessibleTeams);
  const teamId = currentTeam.id;

  // this page param
  const [loadError, setLoadError] = useState<ServiceError | null>(null);
  const [error, setError] = useState<ServiceError | null>(null);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [editingTeam, setEditingTeam] = useState<Team | null>(null);
  const [conditions, setConditions] = useState<
    AdminQueryCondition & CommonPaginationData
  >({
    ...defaultCondition,
    ...parseQueryParam(router.query),
    ...services.localStorage.defaultPaginationData(
      currentUser.id,
      router.query,
    ),
  });
  const [numberOfTotalItems, setNumberOfTotalItems] = useState<number>(0);
  const [isInitialized, setIsInitialized] = useState<boolean>(false);
  // const [userRoleMap, setUserRoleMap] = useState<{ [key: string]: AppRoles }>({})  // user_id -> AppRoles

  // modal data
  const [addProfileModalParam, setAddProfileModalParam] =
    useState<InviteProfileModalParam>({
      ...inviteProfileModalParamDefault(currentTeam),
    });
  const [userToDelete, setUserToDelete] = useState<User | null>(null);
  const [userToReactivate, setUserToReactivate] = useState<User | null>(null);
  const [isEditTeamModalOpen, setIsEditTeamModalOpen] =
    useState<boolean>(false);

  // OK modal
  const [isOkModalOpen, setIsOkModalOpen] = useState<boolean>(false);
  const [okModalText, setOkModalText] = useState<string>('');

  const [users, setUsers] = useState<User[]>([]);

  const [anchorEl, setAnchorEl] = React.useState<null | HTMLElement>(null);
  const [selectedProfileId, setSelectedProfileId] = useState<string | null>(
    null,
  );

  const hasManagementWriteAccess = User.isAccessible(
    currentUser,
    teamId,
    'management',
    'write',
    true,
  );

  const sortOptions = useMemo((): {
    name: string;
    value: UserSortType;
  }[] => {
    return [
      {
        name: translate('order_newest_first'),
        value: 'recent',
      },
      {
        name: translate('order_oldest_first'),
        value: 'oldest',
      },
      {
        name: translate('order_name'),
        value: 'name',
      },
      {
        name: translate('order_name_desc'),
        value: 'nameDesc',
      },
    ];
  }, []);

  const reloadTeam = async (team: Team) => {
    dispatch(
      userDataActions.setTeams({
        teams: [..._.filter(teams, (team) => team.id != teamId), team],
      }),
    );
  };

  const openMenu = (event: React.MouseEvent<HTMLElement>, user: User) => {
    setAnchorEl(event.currentTarget);
    setSelectedProfileId(user.id);
  };

  const closeMenu = () => {
    setAnchorEl(null);
    setSelectedProfileId(null);
  };

  const getProfilesOfTeam = async () => {
    if (!_.isString(teamId)) {
      return;
    }

    const usersResult = await services.default.user.getUsersOfTeam(teamId, {
      keyword: conditions.keyword,
      sort: conditions.sort,
      offset: conditions.rowsPerPage * conditions.currentPage,
      pageSize: conditions.rowsPerPage,
    });
    if (usersResult.error) {
      setLoadError(usersResult.error);
      return;
    }
    setLoadError(null);
    setUsers(usersResult.users);

    setNumberOfTotalItems(usersResult.total);
  };

  const updateQueryParameters = (
    conds: AdminQueryCondition & CommonPaginationData,
  ) => {
    const param = buildQueryParam(conds);
    PathUtil.routerPushOrReplaceWithPaginationData(
      router,
      conds.currentPage,
      PAGE_INFO.ADMIN.href(teamId, param),
    );
  };

  const initialize = async () => {
    try {
      const parsed = {
        ...parseQueryParam(router.query),
        ...services.localStorage.defaultPaginationData(
          currentUser.id,
          router.query,
        ),
      };
      setConditions({
        ...conditions,
        ...parsed,
      });
      updateQueryParameters({
        ...parsed,
        searchTrigger: new Date(),
      });
    } finally {
      setIsInitialized(true);
    }
  };

  // This must be configured for browser back.
  useEffect(() => {
    if (!isInitialized) {
      return;
    }
    // Important: Call after setConditions to trigger (*1)
    const parsed = parseQueryParam(router.query);
    setConditions({
      ...conditions,
      ...parsed,
      searchTrigger: new Date(),
    });
  }, [router.query]); // browser back -> trigger by paginationData

  useEffect(() => {
    // (*1
    if (!isInitialized) {
      return;
    }
    getProfilesOfTeam();
  }, [conditions.searchTrigger]);

  useEffect(() => {
    reloader.reloadIfNeeded();
    initialize();
  }, [currentUser]);

  return (
    // mbはFABのため
    <Container sx={{ mb: 10 }}>
      <Stack direction="column" spacing={4}>
        {/* [MODAL] */}
        {
          // Edit Team Player
          _.isNull(editingUser) ? (
            ''
          ) : (
            <EditProfileModal
              teamId={teamId}
              selectedRole={
                (_.first(editingUser.givenUserRoles[teamId])?.roleGroup.name ??
                  null) as AppRoles | null
              }
              targetUser={editingUser}
              onDiscard={() => {
                setEditingUser(null);
              }}
              onSave={() => {
                setEditingUser(null);
                setConditions({
                  ...conditions,
                  searchTrigger: new Date(),
                });
              }}
            />
          )
        }

        <InviteProfileModal
          param={addProfileModalParam}
          setParam={setAddProfileModalParam}
          onSuccess={() => {
            getProfilesOfTeam();
            setConditions({
              ...conditions,
              searchTrigger: new Date(),
            });
          }}
        />

        <DeactivateProfileModal
          teamId={teamId}
          user={userToDelete ?? null}
          onClose={() => {
            setUserToDelete(null);
            setConditions({
              ...conditions,
              searchTrigger: new Date(),
            });
          }}
          onFailed={() => {
            setIsOkModalOpen(true);
            setOkModalText(translate('failed_to_remove_the_user'));
          }}
          onSuccess={() => {
            setIsOkModalOpen(true);
            setOkModalText(translate('the_user_has_been_removed'));
          }}
        />

        <ReactivateUserModal
          teamId={teamId}
          profile={userToReactivate?.profile ?? null}
          onClose={() => {
            setUserToReactivate(null);
            setConditions({
              ...conditions,
              searchTrigger: new Date(),
            });
          }}
          onFailed={() => {
            setIsOkModalOpen(true);
            setOkModalText(translate('failed_to_re_add_the_user'));
          }}
          onSuccess={() => {
            setIsOkModalOpen(true);
            setOkModalText(translate('the_user_has_been_re_added'));
          }}
        />

        {editingTeam && (
          <EditTeamModal
            teamId={currentTeam.id}
            defaultData={{
              name: currentTeam.name!,
              previewUrl: currentTeam.presignedImageUrl,
            }}
            isOpen={isEditTeamModalOpen}
            setIsOpen={setIsEditTeamModalOpen}
            onSuccess={(team: Team) => {
              reloadTeam(team);
            }}
            onCancel={() => {
              setEditingTeam(null);
            }}
          />
        )}

        <OkModal
          isOpen={isOkModalOpen}
          setIsOpen={setIsOkModalOpen}
          title={okModalText}
        />

        {/* [HEADER] */}
        <Stack direction="row" alignItems="center" sx={{ py: 1 }}>
          <Image
            src={
              currentTeam?.presignedImageUrl ??
              AppConstants.NO_IMAGE_2ND_BASE_URL
            }
            alt=""
            width="120"
            height="120"
          />
          <Stack
            direction="row"
            sx={{ alignItems: 'center', flex: 1, px: 3, py: 1 }}
          >
            {/* multiple team:チーム名, single team:ユーザー管理 */}
            <Typography variant="h1">
              {currentTeam.teamType === TeamType.SINGLE
                ? translate('page_admin')
                : currentTeam?.name}
            </Typography>
            {hasManagementWriteAccess ? (
              <Button
                sx={{ color: '#707070', textDecoration: 'underline' }}
                color="neutral"
                onClick={() => {
                  setEditingTeam(currentTeam);
                  setIsEditTeamModalOpen(true);
                }}
              >
                {translate('edit')}
              </Button>
            ) : (
              ''
            )}
            <ValidationError
              error={error}
              pos={['name']}
              sx={{ ml: 1, mt: 1 }}
            />
          </Stack>
        </Stack>
        <Divider sx={{ mt: 2 }} />

        {/* [MAIN CONTENT] */}
        <Card sx={{ backgroundColor: 'white', p: 2 }}>
          <Stack
            direction={{ xs: 'column', md: 'row-reverse' }}
            spacing={2}
            justifyContent="space-between"
          >
            <DefaultSearchField
              value={conditions.keyword}
              onSearch={() => {
                const newData = {
                  ...conditions,
                  currentPage: 0,
                };
                updateQueryParameters(newData);
              }}
              onChange={(e) => {
                setConditions({
                  ...conditions,
                  keyword: e.target.value,
                });
              }}
            />
            <Grid container direction="row" spacing={1} sx={{ flex: 1 }}>
              <Grid size="auto">
                <FormControl size="small" variant="standard">
                  <Select
                    value={conditions.sort}
                    onChange={(e) => {
                      const newData = {
                        ...conditions,
                        sort: e.target.value as UserSortType,
                        currentPage: 0,
                      };
                      setConditions(newData);
                      updateQueryParameters(newData);
                    }}
                  >
                    {sortOptions.map((x) => {
                      return (
                        <MenuItem key={x.value} value={x.value}>
                          {x.name}
                        </MenuItem>
                      );
                    })}
                  </Select>
                </FormControl>
              </Grid>
            </Grid>
          </Stack>

          {loadError ? (
            <CriticalError error={loadError} />
          ) : (
            <TableContainer component={Paper}>
              <Table
                aria-label="a dense table"
                sx={{
                  '.MuiTableCell-root': { overflowWrap: 'anywhere' },
                }}
              >
                <TableHead>
                  <TableRow>
                    <TableCell align="left">{translate('name')}</TableCell>
                    <TableCell align="left">{translate('email')}</TableCell>
                    <TableCell align="left">{translate('role')}</TableCell>
                    <TableCell align="left">{/* button */}</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {users.map((user) => (
                    <TableRow
                      key={user.id}
                      sx={{
                        '&:last-child td, &:last-child th': { border: 0 },
                        background: _.first(user.givenUserRoles[teamId])
                          ?.deleteFlag
                          ? 'darkgray'
                          : 'inherit',
                      }}
                    >
                      <TableCell align="left">
                        <Stack direction="row" alignItems="center" spacing={1}>
                          <ImageOrAvatar
                            url={user.profile.presignedImageUrl}
                            height={30}
                            width={30}
                          />
                          <Typography
                            sx={{
                              textDecoration: 'none',
                              color: 'text.primary',
                            }}
                            variant="inherit"
                          >
                            {user.profile.username ?? '-'}
                          </Typography>
                        </Stack>
                      </TableCell>
                      <TableCell align="left">{user.email}</TableCell>
                      <TableCell align="left">
                        <Stack direction="row" spacing={1}>
                          {_.first(user.givenUserRoles[teamId])?.deleteFlag ? (
                            <>{translate('deactivated')}</>
                          ) : (
                            <>
                              {_.map(
                                user.givenUserRoles[teamId] ?? [],
                                (userRole, idx) => {
                                  return (
                                    <Box key={idx}>
                                      {userRoleToDispName(
                                        userRole.roleGroup.name,
                                      ) ?? ''}
                                    </Box>
                                  );
                                },
                              )}
                            </>
                          )}
                        </Stack>
                      </TableCell>
                      <TableCell align="right">
                        {hasManagementWriteAccess ? (
                          <>
                            <Button
                              color="neutral"
                              onClick={(e) => {
                                if (_.isNil(anchorEl)) {
                                  openMenu(e, user);
                                } else {
                                  closeMenu();
                                }
                              }}
                            >
                              <MoreHoriz />
                            </Button>

                            <Menu
                              onClose={closeMenu}
                              anchorEl={anchorEl}
                              open={selectedProfileId === user.id}
                            >
                              {_.first(user.givenUserRoles[teamId])
                                ?.deleteFlag && currentUser.id != user.id ? (
                                <>
                                  <MenuItem
                                    onClick={() => {
                                      // banned and not the same user as currentUser
                                      setUserToReactivate(user);
                                      closeMenu();
                                    }}
                                  >
                                    {translate('reactivate')}
                                  </MenuItem>
                                </>
                              ) : (
                                ''
                              )}
                              {!_.first(user.givenUserRoles[teamId])
                                ?.deleteFlag ? (
                                <MenuItem
                                  onClick={() => {
                                    // not banned
                                    setEditingUser(user);
                                    closeMenu();
                                  }}
                                >
                                  {translate('edit')}
                                </MenuItem>
                              ) : (
                                ''
                              )}
                              {!_.first(user.givenUserRoles[teamId])
                                ?.deleteFlag && currentUser.id != user.id ? (
                                <>
                                  <MenuItem
                                    onClick={() => {
                                      // not banned and not the same user as currentUser
                                      setUserToDelete(user);
                                      closeMenu();
                                    }}
                                  >
                                    {translate('deactivate')}
                                  </MenuItem>
                                </>
                              ) : (
                                ''
                              )}
                            </Menu>
                          </>
                        ) : (
                          ''
                        )}
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          )}
          <CommonPagination
            user={currentUser}
            numberOfTotalItems={numberOfTotalItems}
            commonPaginationData={{
              currentPage: conditions.currentPage,
              rowsPerPage: conditions.rowsPerPage,
            }}
            onChange={(data) => {
              updateQueryParameters({
                ...conditions,
                ...data,
              });
            }}
          />
        </Card>
      </Stack>
      {hasManagementWriteAccess && (
        <FloatingButton
          icon={<PersonAddAlt />}
          title={translate('invite_member')}
          onClick={() => {
            setAddProfileModalParam({
              ...inviteProfileModalParamDefault(currentTeam),
              isEditing: true,
            });
          }}
        />
      )}
    </Container>
  );
}

export default function Page() {
  const { router } = useServicesHook();
  const currentUser = useSelector((state) => state.user.me);
  const teams = useSelector((state) => state.user.accessibleTeams);
  const [team, setTeam] = useState<Team>();
  const teamId = router.query.team_id?.toString();

  useEffect(() => {
    if (!teamId) {
      return;
    }
    setTeam(teams.find((x) => x.id == teamId));
  }, [teamId, teams]);

  if (!team) {
    return <AccessDenied />;
  }

  return (
    currentUser &&
    team && <PageInner currentUser={currentUser} currentTeam={team} />
  );
}

Page.getLayout = function getLayout(page: ReactElement) {
  return <ConsoleLayout>{page}</ConsoleLayout>;
};

