                          <>
                            <Button
                              color="neutral"
                              onClick={(e) => {
                                if (_.isNil(anchorEl)) {
                                  openMenu(e, user);
                                } else {
                                  closeMenu();
                                }
                              }}
                            >
                              <MoreHoriz />
                            </Button>

                            <Menu
                              onClose={closeMenu}
                              anchorEl={anchorEl}
                              open={selectedProfileId === user.id}
